INSERT INTO places_fts VALUES ('poi-zhao-louvre', 'La Taverne de Zhao', 'restaurant', 'chinois noodles biang-biang authentique chic', '22 rue Molière, 75001 Paris, France', '', 'À quelques pas du Louvre, cette taverne est sans doute la plus raffinée du groupe. Avec son décor qui mêle pierres apparentes et design contemporain, elle offre une parenthèse de sérénité au cœur du 1er arrondissement. On y déguste les spécialités de Xi''an avec une élégance rare.');
