915kcoLFcMqSBohfMjHH0jiiarLENkVJvBvVwtSb7tnNH20BUWf7iUPD1PDS&key=AIzaSyDpkuHPvH-X8hZrLrpZbyC2Hi39iAfrLKM"]', NULL, '{"insider_tip":"Hôtel Salé magnifique. La collection d''œuvres est unique.","specials":{"cuisine":[],"drinks":[]}}', 'Installé dans l''Hôtel Salé, le plus grand et le plus extravagant des hôtels particuliers du Marais (construit par un collecteur de l''impôt sur le sel au XVIIe), le musée abrite la plus riche collection mondiale d''œuvres de Picasso. La rénovation a sublimé le dialogue entre l''architecture baroque (escalier d''honneur monumental) et la modernité radicale des œuvres. On y traverse toutes les périodes du maître, de ses débuts académiques au cubisme et au surréalisme. Le café sur le toit et le jardin sont des havres de paix appréciables après la visite.', 'Hôtel Salé magnifique. La collection d''œuvres est unique.', 'À proximité', '[]', '[]', NULL, NULL);
INSERT INTO places_fts VALUES ('poi-060', 'Musée National Picasso-Paris', 'museum', 'musee', '5 Rue de Thorigny', '', 'Installé dans l''Hôtel Salé, le plus grand et le plus extravagant des hôtels particuliers du Marais (construit par un collecteur de l''impôt sur le sel au XVIIe), le musée abrite la plus riche collection mondiale d''œuvres de Picasso. La rénovation a sublimé le dialogue entre l''architecture baroque (escalier d''honneur monumental) et la modernité radicale des œuvres. On y traverse toutes les périodes du maître, de ses débuts académiques au cubisme et au surréalisme. Le café sur le toit et le jardin sont des havres de paix appréciables après la visite.');
INSERT INTO places VALUES ('poi-117', 'Musée Carnavalet', 'musee-carnavalet', 'museum', 'musée d''histoire', 'culturel', 48.857067, 2.362858, 3, '23 Rue de Sévigné', '#c499ff', 'pin', 1, 4.7, 0, 'https://maps.googleapis.com/maps/api/place/photo?maxwidth=1600&photoreference=AcnlKN30KIglgyzAQ5W9QgBmkNRF1vko8GSqG3NmgPVERhzGtqKwbFxmwuV6meGdChbQgfLGoX9N_Nqy3dYXWwgM3hXHsM9Kvhvqc4zDUg7CKjFXuN0eqDCwt8ZsKMsTNNK1ExTvJx7Ojc045q_anvVFyOJV60o9qj0X2D-ENcDA0ahy440ORH3qSqVXyVwPtLboc0jF1E_5tVxPE2vNN2FXt443ftFy0JaPeEj6J7uhf5yhHy7V5ubGBBEeaEnMIE3TwGT3kJN5m9G-dFMMtVSAygb17ThAOEBNNDSd1ijI-Tnse9qnirogDUTzC9Y31CqOeTiFEogZP-jjVoa172GFsn6HeJ750FpahCPLxoTAJXGqVwGxo1Zip6MloNTfoGZQrLBJvdBS2iowBHHBz34ZroqacxyGzOGKC-ii-_1SdCz7Di0Q&key=AIzaSyDpkuHPvH-X8hZrLrpZbyC2Hi39iAfrLKM', NULL, 0, 1, '€', 0, 0, 0, 0, 0, 50, '{"chill":8,"festif":4,"culturel":25}', '{}', '["museum","musée d''histoire"]', '{"standard":"","display":"","detailed":""}', '{"reservation_policy":null,"accessibility":false,"wifi":false,"opening_hours_raw":"","action_type":"site","action_url":"","terrace":false,"happy_hour":null}', '{"avg_budget":2,"is_free":true,"pint_price":0,"cocktail_price":0,"coffee_price":0,"dish_price":0,"menu_items":[]}', '{"hero":"https://maps.googleapis.com/maps/api/place/photo?maxwidth=1600&photoreference=AcnlKN30KIglgyzAQ5W9QgBmkNRF1vko8GSqG3NmgPVERhzGtqKwbFxmwuV6meGdChbQgfLGoX9N_Nqy3dYXWwgM3hXHsM9Kvhvqc4zDUg7CKjFXuN0eqDCwt8ZsKMsTNNK1ExTvJx7Ojc045q_anvVFyOJV60o9qj0X2D-ENcDA0ahy440ORH3qSqVXyVwPtLboc0jF1E_5tVxPE2vNN2FXt443ftFy0JaPeEj6J7uhf5yhHy7V5ubGBBEeaEnMIE3TwGT3kJN5m9G-dFMMtVSAygb17ThAOEBNNDSd1ijI-Tnse9qnirogDUTzC9Y31CqOeTiFEogZP-jjVoa172GFsn6HeJ750FpahCPLxoTAJXGqVwGxo1Zip6MloNTfoGZQrLBJvdBS2iowBHHBz34ZroqacxyGzOGKC-ii-_1SdCz7Di0Q&key=AIzaSyDpkuHPvH-X8hZrLrpZbyC2Hi39iAfrLKM","gallery":[]}', '[]', NULL, '{"insider_tip":"L''entrée est gratuite tous les premiers dimanches du mois.","specials":{"cuisine":[],"drinks":[]}}', 'Logé dans deux hôtels particuliers somptueux au cœur du Marais, ce musée raconte l''histoire de Paris depuis ses origines jusqu''à nos jours. Après une rénovation magistrale, le parcours est devenu une flânerie poétique à travers des décors d''époque reconstitués, des enseignes médiévales et des souvenirs de la Révolution. Le jardin intérieur est un havre de paix insoupçonnable, parfait pour une pause hors du temps.', 'L''entrée est gratuite tous les premiers dimanches du mois.', 'À proximité', '[]', '[]', NULL, NULL);
INSERT INTO places_fts VALUES ('poi-117', 'Musée Carnavalet', 'museum', 'musée d''histoire', '23 Rue de Sévigné', '', 'Logé dans deux hôtels particuliers somptueux au cœur du Marais, ce musée raconte l''histoire de Paris depuis ses origines jusqu''à nos jours. Après une rénovation magistrale, le parcours est devenu une flânerie poétique à travers des décors d''époque reconstitués, des enseignes médiévales et des souvenirs de la Révolution. Le jardin intérieur est un havre de paix insoupçonnable, parfait pour une pause hors du temps.');
