INSERT INTO places VALUES ('poi-130', 'Café de la Nouvelle Mairie', 'cafe-nouvelle-mairie', 'café', 'cafe-terrasse', 'chill', 48.845467, 2.344825, 5, '19 Rue des Fossés Saint-Jacques', '#8ccaf7', 'pin', 1, 3.7, 0, 'https://maps.googleapis.com/maps/api/place/photo?maxwidth=1600&photoreference=AcnlKN1PWloJmpAufbVHD1PC5nAJxc6ikp19PDUAnKP-A3u48ozNEky3KdorLe4U2bWjzHU1KrFD4bpvQKpzVF0zzCfvcwdCIQTaDUXvKKYxNxEmX7KkJF31mzZXdOJItHzEjtgUnLXx7lkSxaLgm7rDp2Pxyq8khVBzjKE4Fx5fPZfNqWvC5GyjvtnlvQsZYrgyOfRZaOMtaTsTLjV4eAMTK9dRgQFRIyKoPjk_S3zlxYF2XG-wXzSO4fvTjRcy3_hD05RQ-6jFyyE2cZYbixIhV9fvPNoAIjApb6iMlI8lgABqkw&key=AIzaSyDpkuHPvH-X8hZrLrpZbyC2Hi39iAfrLKM', NULL, 3, 0, '€', NULL, NULL, NULL, 3, 16, 50, '{"chill":23,"festif":4,"culturel":5}', '{}', '["café","cafe-terrasse"]', '{"standard":"","display":"","detailed":""}', '{"reservation_policy":null,"accessibility":false,"wifi":false,"opening_hours_raw":"","action_type":"site","action_url":"","terrace":false,"happy_hour":null}', '{"avg_budget":15,"is_free":false,"pint_price":0,"cocktail_price":0,"coffee_price":3,"dish_price":16,"menu_items":[]}', '{"hero":"https://maps.googleapis.com/maps/api/place/photo?maxwidth=1600&photoreference=AcnlKN1PWloJmpAufbVHD1PC5nAJxc6ikp19PDUAnKP-A3u48ozNEky3KdorLe4U2bWjzHU1KrFD4bpvQKpzVF0zzCfvcwdCIQTaDUXvKKYxNxEmX7KkJF31mzZXdOJItHzEjtgUnLXx7lkSxaLgm7rDp2Pxyq8khVBzjKE4Fx5fPZfNqWvC5GyjvtnlvQsZYrgyOfRZaOMtaTsTLjV4eAMTK9dRgQFRIyKoPjk_S3zlxYF2XG-wXzSO4fvTjRcy3_hD05RQ-6jFyyE2cZYbixIhV9fvPNoAIjApb6iMlI8lgABqkw&key=AIzaSyDpkuHPvH-X8hZrLrpZbyC2Hi39iAfrLKM","gallery":[]}', '[]', NULL, '{"insider_tip":"L''adresse préférée des locaux, loin des foules habituelles.","specials":{"cuisine":[],"drinks":[]}}', 'La quintessence du bistrot de quartier parisien, celui dont on rêve quand on pense à la Rive Gauche. Face à une charmante petite place, sa terrasse est le spot idéal pour observer la vie du 5ème arrondissement. La sélection de vins nature est exceptionnelle, l''accueil est fraternel et les petites assiettes de saison sont d''une justesse absolue. C''est un lieu où l''on vient pour un café matinal et où l''on finit par dîner, capturé par sa douceur de vivre.', 'L''adresse préférée des locaux, loin des foules habituelles.', 'À proximité', '[]', '[]', NULL, NULL);
INSERT INTO places_fts VALUES ('poi-130', 'Café de la Nouvelle Mairie', 'café', 'cafe-terrasse', '19 Rue des Fossés Saint-Jacques', '', 'La quintessence du bistrot de quartier parisien, celui dont on rêve quand on pense à la Rive Gauche. Face à une charmante petite place, sa terrasse est le spot idéal pour observer la vie du 5ème arrondissement. La sélection de vins nature est exceptionnelle, l''accueil est fraternel et les petites assiettes de saison sont d''une justesse absolue. C''est un lieu où l''on vient pour un café matinal et où l''on finit par dîner, capturé par sa douceur de vivre.');
