rinks":["Vins Italiens","Spritz"],"must_eat":"Pizza au feu de bois & Gnocchis Pistache.","expert_catchline":"L''Italie authentique au feu de bois en plein Saint-Michel."}}', 'Niché dans la pittoresque rue Saint-Séverin, le Rim Café est une escale italienne authentique loin des pièges à touristes classiques du quartier. Sa spécialité ? Les pizzas cuites dans un imposant four au feu de bois visible dès l''entrée. L''accueil y est chaleureux, souvent orchestré par une équipe passionnée qui n''hésite pas à recommander les gnocchis à la pistache, devenus cultes parmi les habitués. La petite terrasse permet de profiter de l''animation du Quartier Latin tout en savourant une cuisine généreuse faite maison.', '• Ne passez pas à côté des Gnocchis à la crème de pistache, c''est la pépite absolue de la carte.
INSERT INTO places_fts VALUES ('poi-rim-cafe', 'Rim Café', 'restaurant', 'italien pizza pates saint-michel terrasse fait-maison', '38 Rue Saint-Séverin, 75005 Paris', '', 'Niché dans la pittoresque rue Saint-Séverin, le Rim Café est une escale italienne authentique loin des pièges à touristes classiques du quartier. Sa spécialité ? Les pizzas cuites dans un imposant four au feu de bois visible dès l''entrée. L''accueil y est chaleureux, souvent orchestré par une équipe passionnée qui n''hésite pas à recommander les gnocchis à la pistache, devenus cultes parmi les habitués. La petite terrasse permet de profiter de l''animation du Quartier Latin tout en savourant une cuisine généreuse faite maison.');
INSERT INTO places VALUES ('poi-131', 'Shakespeare and Company Café', 'shakespeare-cafe', 'café', 'cafe-litteraire', 'chill', 48.852617, 2.347218, 5, '37 Rue de la Bûcherie', '#8ccaf7', 'pin', 1, 4.1, 0, 'https://maps.googleapis.com/maps/api/place/photo?maxwidth=1600&photoreference=AcnlKN1CzIunaikQ6grege_XJuK7l_Eu6Upu45EXk_uXvlsa3K-74mkakUuZGTT_rQnf8cOJXLwzd8BHEOUvmpjCAiAwdmsUv1cx-UO8Fx0GIe7BfwcjkPwrPaQwCz9UIIa-CVLbb_tErP9z66G15EXrp5LUvY0ywzJTZDmRah7Uo5mHtIc_nlZn9WrF9l3QoEnOqbDrVLuU41IV7NGsra_mJSZg23wwynay2PkSp_C9329z3jAML1ROX1n9bMADao0BIdg3lAIyzThsWmrQh9H4Z5fgH3jy7S5jdiWklpJpvuHQfHn7W2Bg_T6SNOfMNJH9_N5N33SkLL5Vy9AiFVO1qB_-SKgIPZgEd85bfCs1IhgioCqyMjZOuBJTrr98NQ7JfXfigaZGXBL1iFjFAjINK3e1k36hcfbSXs0QlzQPzvOkYipMY0_K6kbz5ZklicR8&key=AIzaSyDpkuHPvH-X8hZrLrpZbyC2Hi39iAfrLKM', NULL, 4.5, 0, '€', NULL, NULL, NULL, 4.5, 0, 50, '{"chill":23,"festif":4,"culturel":5}', '{}', '["café","cafe-litteraire"]', '{"standard":"","display":"","detailed":""}', '{"reservation_policy":null,"accessibility":false,"wifi":false,"opening_hours_raw":"","action_type":"site","action_url":"","terrace":false,"happy_hour":null}', '{"avg_budget":15,"is_free":false,"pint_price":0,"cocktail_price":0,"coffee_price":4.5,"dish_price":0,"menu_items":[]}', '{"hero":"https://maps.googleapis.com/maps/api/place/photo?maxwidth=1600&photoreference=AcnlKN1CzIunaikQ6grege_XJuK7l_Eu6Upu45EXk_uXvlsa3K-74mkakUuZGTT_rQnf8cOJXLwzd8BHEOUvmpjCAiAwdmsUv1cx-UO8Fx0GIe7BfwcjkPwrPaQwCz9UIIa-CVLbb_tErP9z66G15EXrp5LUvY0ywzJTZDmRah7Uo5mHtIc_nlZn9WrF9l3QoEnOqbDrVLuU41IV7NGsra_mJSZg23wwynay2PkSp_C9329z3jAML1ROX1n9bMADao0BIdg3lAIyzThsWmrQh9H4Z5fgH3jy7S5jdiWklpJpvuHQfHn7W2Bg_T6SNOfMNJH9_N5N33SkLL5Vy9AiFVO1qB_-SKgIPZgEd85bfCs1IhgioCqyMjZOuBJTrr98NQ7JfXfigaZGXBL1iFjFAjINK3e1k36hcfbSXs0QlzQPzvOkYipMY0_K6kbz5ZklicR8&key=AIzaSyDpkuHPvH-X8hZrLrpZbyC2Hi39iAfrLKM","gallery":[]}', '[]', NULL, '{"insider_tip":"L''adresse préférée des locaux, loin des foules habituelles.","specials":{"cuisine":[],"drinks":[]}}', 'Adossé à la librairie anglophone la plus célèbre du monde, ce café offre une vue imprenable sur Notre-Dame à travers ses grandes vitres. Entre les pâtisseries anglo-saxonnes (incroyable lemon pie!), les cafés d''exception et les livres qui traînent sur les tables, c''est le refuge parfait pour les amoureux des lettres. On y respire l''héritage de la Beat Generation dans une version moderne, lumineuse et délicieusement gourmande.', 'L''adresse préférée des locaux, loin des foules habituelles.', 'À proximité', '[]', '[]', NULL, NULL);
INSERT INTO places_fts VALUES ('poi-131', 'Shakespeare and Company Café', 'café', 'cafe-litteraire', '37 Rue de la Bûcherie', '', 'Adossé à la librairie anglophone la plus célèbre du monde, ce café offre une vue imprenable sur Notre-Dame à travers ses grandes vitres. Entre les pâtisseries anglo-saxonnes (incroyable lemon pie!), les cafés d''exception et les livres qui traînent sur les tables, c''est le refuge parfait pour les amoureux des lettres. On y respire l''héritage de la Beat Generation dans une version moderne, lumineuse et délicieusement gourmande.');
