h) pour éviter la queue sur le boulevard.
INSERT INTO places_fts VALUES ('poi-le-petit-bouillon-vavin', 'Le Petit Bouillon Vavin', 'restaurant', 'français bouillon traditionnel vibrant art-deco', '119 Bd du Montparnasse, 75006 Paris, France', '', 'Le Petit Bouillon Vavin est une enclave d''effervescence joyeuse au cœur du Montparnasse historique. Sous son haut plafond Art Déco, on revit l''âge d''or des brasseries populaires parisiennes : service en tablier blanc, nappes en papier et une cuisine française authentique servie à une vitesse record. C''est bruyant, c''est vivant, c''est Paris.');
