INSERT INTO places_fts VALUES ('poi-zhao-st-germain', 'La Taverne de Zhao', 'restaurant', 'chinois noodles biang-biang authentique chic', '82 rue Mazarine, 75006 Paris, France', '', 'À deux pas de l''Odéon, cette taverne est l''une des plus esthétiques du groupe. Inaugurée en juillet 2024, elle s''intègre au chic du 6e arrondissement tout en conservant l''âme brute de Xi''an. Le lieu est idéal pour un dîner élégant, sublimant l''art des nouilles Biang Biang dans un cadre épuré.');
