kmSv_G9TCCpwe500rGF4EmT30dkB6NwBe2nEx8GjvYtH2emIRlnMPw18_u6HNQVQr5G4KPmyr5YObueXzcRwYfUPnsQ4x_B3&key=AIzaSyDpkuHPvH-X8hZrLrpZbyC2Hi39iAfrLKM"]', NULL, '{"insider_tip":"• Ne commandez pas trop d''entrées : le riz et les 4 types de banchans (souvent kimchi, pousses de soja, radis marine, algues) sont servis à volonté avec tous les barbecues.\n• Si vous n''êtes pas habitué à la cuisson sur grill, les serveurs sont très didactiques et n''hésitent pas à prendre les pinces pour vous montrer le timing parfait.\n• Évitez le créneau de 20h pile sans réservation, le lieu est très prisé par les étudiants de la faculté d''Assas voisine.","specials":{"cuisine":["Coréen","Barbecue","Bibimbap"],"drinks":["Soju","Bière","Soft"],"must_eat":"Le Barbecue de Bœuf mariné & les Mandu maison.","expert_catchline":"L''immersion coréenne parfaite à Assas : BBQ généreux et banchans illimités."}}', 'Situé à deux pas du Jardin du Luxembourg, Joayo Luxembourg est l''une des adresses les plus authentiques de la rive gauche pour le Barbecue Coréen. Le décor, mariant briques apparentes et boiseries chaleureuses, crée une atmosphère de taverne séoulite moderne. Chaque table est équipée de son propre système de grillade intégré, permettant une immersion totale. La promesse du lieu tient dans la fraîcheur des marinades et la générosité des banchan (petits plats d''accompagnement typiques) qui ponctuent tout le repas.', '• Ne commandez pas trop d''entrées : le riz et les 4 types de banchans (souvent kimchi, pousses de soja, radis marine, algues) sont servis à volonté avec tous les barbecues.
INSERT INTO places_fts VALUES ('poi-joayo-lux-75006', 'Joayo Luxembourg', 'restaurant', 'coreen barbecue bibimbap fait-maison', '54 Rue d''Assas, 75006 Paris', '', 'Situé à deux pas du Jardin du Luxembourg, Joayo Luxembourg est l''une des adresses les plus authentiques de la rive gauche pour le Barbecue Coréen. Le décor, mariant briques apparentes et boiseries chaleureuses, crée une atmosphère de taverne séoulite moderne. Chaque table est équipée de son propre système de grillade intégré, permettant une immersion totale. La promesse du lieu tient dans la fraîcheur des marinades et la générosité des banchan (petits plats d''accompagnement typiques) qui ponctuent tout le repas.');
INSERT INTO places VALUES ('poi-136', 'Les Éditeurs', 'les-editeurs', 'café', 'cafe-litteraire', 'chill', 48.851941, 2.338382, 6, '4 Carr de l''Odéon', '#8ccaf7', 'pin', 1, 4.3, 0, 'https://maps.googleapis.com/maps/api/place/photo?maxwidth=1600&photoreference=AcnlKN0Rk_4pTy7y5qxoV_-GnEtAfJM1kJ7ca1DVWmul0KnEvQEbLkEm5JeunkZ1ASzLvoWbF1N6bH_bfnkEHfySor-5sCKoaEU8XcOjA4VHSiNPHZ8H8xBV-lDxORGzJcRyJYvVvCXrwcZMGsrq8nkx4GsdULEG_T0aJ9R3Y5c2MT7k86XM4KrL5PCscS45MWs96Iy51s8rCjvmDZPVNC_ynt1tH0skv2ykEOjIHvMEaeyWHmzPkcPcg7-J8BH3uwIFTaZdQmAKc1B3C6rjtU2IylziAn2sx3BdHWPgzLw0EGTlqw&key=AIzaSyDpkuHPvH-X8hZrLrpZbyC2Hi39iAfrLKM', NULL, 3.6, 0, '€', NULL, NULL, NULL, 3.6, 22, 50, '{"chill":23,"festif":4,"culturel":5}', '{}', '["café","cafe-litteraire"]', '{"standard":"","display":"","detailed":""}', '{"reservation_policy":null,"accessibility":false,"wifi":false,"opening_hours_raw":"","action_type":"site","action_url":"","terrace":false,"happy_hour":null}', '{"avg_budget":15,"is_free":false,"pint_price":0,"cocktail_price":0,"coffee_price":3.6,"dish_price":22,"menu_items":[]}', '{"hero":"https://maps.googleapis.com/maps/api/place/photo?maxwidth=1600&photoreference=AcnlKN0Rk_4pTy7y5qxoV_-GnEtAfJM1kJ7ca1DVWmul0KnEvQEbLkEm5JeunkZ1ASzLvoWbF1N6bH_bfnkEHfySor-5sCKoaEU8XcOjA4VHSiNPHZ8H8xBV-lDxORGzJcRyJYvVvCXrwcZMGsrq8nkx4GsdULEG_T0aJ9R3Y5c2MT7k86XM4KrL5PCscS45MWs96Iy51s8rCjvmDZPVNC_ynt1tH0skv2ykEOjIHvMEaeyWHmzPkcPcg7-J8BH3uwIFTaZdQmAKc1B3C6rjtU2IylziAn2sx3BdHWPgzLw0EGTlqw&key=AIzaSyDpkuHPvH-X8hZrLrpZbyC2Hi39iAfrLKM","gallery":[]}', '[]', NULL, '{"insider_tip":"L''adresse préférée des locaux, loin des foules habituelles.","specials":{"cuisine":[],"drinks":[]}}', 'Installé dans une magnifique bâtisse à l''angle du Boulevard Saint-Germain, Les Éditeurs est le café littéraire par excellence. Entre les milliers de livres qui ornent les murs, les fauteuils en cuir rouge et la vue sur l''Odéon, l''ambiance est studieuse et feutrée. On y croise souvent des auteurs et des gens de l''édition, venus discuter de leur prochain manuscrit autour d''un café ou d''un club sandwich exemplaire. Une bulle de culture et de confort parisien.', 'L''adresse préférée des locaux, loin des foules habituelles.', 'À proximité', '[]', '[]', NULL, NULL);
INSERT INTO places_fts VALUES ('poi-136', 'Les Éditeurs', 'café', 'cafe-litteraire', '4 Carr de l''Odéon', '', 'Installé dans une magnifique bâtisse à l''angle du Boulevard Saint-Germain, Les Éditeurs est le café littéraire par excellence. Entre les milliers de livres qui ornent les murs, les fauteuils en cuir rouge et la vue sur l''Odéon, l''ambiance est studieuse et feutrée. On y croise souvent des auteurs et des gens de l''édition, venus discuter de leur prochain manuscrit autour d''un café ou d''un club sandwich exemplaire. Une bulle de culture et de confort parisien.');
