pZbyC2Hi39iAfrLKM"]', NULL, '{"insider_tip":"Le jardin de sculptures est accessible pour 4€ (sans le musée).","specials":{"cuisine":[],"drinks":[]}}', 'L''Hôtel Biron, où Rodin a vécu et travaillé, est sans doute l''un des plus beaux hôtels particuliers de Paris. Mais la magie opère surtout dans le jardin de sculptures de 3 hectares. Se promener au milieu des rosiers et découvrir le Penseur ou la Porte de l''Enfer en plein air, avec le dôme des Invalides en toile de fond, est un moment de grâce. L''intérieur du musée, baigné de lumière, présente les œuvres en plâtre, marbre et bronze dans leur cadre d''origine. Romantique à souhait.', 'Le jardin de sculptures est accessible pour 4€ (sans le musée).', 'À proximité', '[]', '[]', NULL, NULL);
INSERT INTO places_fts VALUES ('poi-055', 'Musée Rodin', 'museum', 'musee', '77 Rue de Varenne', '', 'L''Hôtel Biron, où Rodin a vécu et travaillé, est sans doute l''un des plus beaux hôtels particuliers de Paris. Mais la magie opère surtout dans le jardin de sculptures de 3 hectares. Se promener au milieu des rosiers et découvrir le Penseur ou la Porte de l''Enfer en plein air, avec le dôme des Invalides en toile de fond, est un moment de grâce. L''intérieur du musée, baigné de lumière, présente les œuvres en plâtre, marbre et bronze dans leur cadre d''origine. Romantique à souhait.');
INSERT INTO places VALUES ('poi-148', 'Musée Maillol', 'musee-maillol', 'museum', 'sculpture', 'culturel', 48.854774, 2.324905, 7, '59-61 Rue de Grenelle', '#c499ff', 'pin', 1, 4.5, 0, 'https://maps.googleapis.com/maps/api/place/photo?maxwidth=1600&photoreference=AcnlKN2OPqOi6vmTo0yddRhc5Zbc9ZAmPm0-s87UKQ0c4MU2bE1szhw9HHJAZuRgPYOTYsO_bSv6nSjazYWrYuLNVajMcQG65D6da3L12YMZxOpKhdCcqsAbiNfVobRbngG6_MOUcPTydjXt51bS-q1lEBSlFL38Nqu53vDFXrYprNUDMW-wLNp4oY401Gmom78dWBe7PUUoZuJPX9pjX0ap4iRewaQ2RvjLgTTNdh03GYfuwi6s8l-KklPCDVNX1MGWBXh1dQrpfxKXchhkjJWHFVABAmcadPPtbuSYpSSHyfKzjw&key=AIzaSyDpkuHPvH-X8hZrLrpZbyC2Hi39iAfrLKM', NULL, 15, 0, '€', NULL, NULL, NULL, 0, 0, 50, '{"chill":7,"festif":4,"culturel":24}', '{}', '["museum","sculpture"]', '{"standard":"","display":"","detailed":""}', '{"reservation_policy":null,"accessibility":false,"wifi":false,"opening_hours_raw":"","action_type":"site","action_url":"","terrace":false,"happy_hour":null}', '{"index_price":15,"avg_budget":15,"is_free":false,"pint_price":0,"cocktail_price":0,"coffee_price":0,"dish_price":0,"menu_items":[]}', '{"hero":"https://maps.googleapis.com/maps/api/place/photo?maxwidth=1600&photoreference=AcnlKN2OPqOi6vmTo0yddRhc5Zbc9ZAmPm0-s87UKQ0c4MU2bE1szhw9HHJAZuRgPYOTYsO_bSv6nSjazYWrYuLNVajMcQG65D6da3L12YMZxOpKhdCcqsAbiNfVobRbngG6_MOUcPTydjXt51bS-q1lEBSlFL38Nqu53vDFXrYprNUDMW-wLNp4oY401Gmom78dWBe7PUUoZuJPX9pjX0ap4iRewaQ2RvjLgTTNdh03GYfuwi6s8l-KklPCDVNX1MGWBXh1dQrpfxKXchhkjJWHFVABAmcadPPtbuSYpSSHyfKzjw&key=AIzaSyDpkuHPvH-X8hZrLrpZbyC2Hi39iAfrLKM","gallery":[]}', '[]', NULL, '{"insider_tip":"L''entrée est gratuite tous les premiers dimanches du mois.","specials":{"cuisine":[],"drinks":[]}}', 'Musée intimiste niché dans l''hôtel particulier de la rue de Grenelle, le Musée Maillol présente l''œuvre sensuelle d''Aristide Maillol. Au-delà des courbes généreuses des sculptures de Dina Vierny, le musée accueille des expositions temporaires prestigieuses et souvent audacieuses. Sa cour intérieure et son escalier monumental en font un lieu de calme et d''élégance architecturale, idéal pour une pause culturelle raffinée au cœur du faubourg Saint-Germain.', 'L''entrée est gratuite tous les premiers dimanches du mois.', 'À proximité', '[]', '[]', NULL, NULL);
INSERT INTO places_fts VALUES ('poi-148', 'Musée Maillol', 'museum', 'sculpture', '59-61 Rue de Grenelle', '', 'Musée intimiste niché dans l''hôtel particulier de la rue de Grenelle, le Musée Maillol présente l''œuvre sensuelle d''Aristide Maillol. Au-delà des courbes généreuses des sculptures de Dina Vierny, le musée accueille des expositions temporaires prestigieuses et souvent audacieuses. Sa cour intérieure et son escalier monumental en font un lieu de calme et d''élégance architecturale, idéal pour une pause culturelle raffinée au cœur du faubourg Saint-Germain.');
INSERT INTO places VALUES ('poi-147', 'Musée d''Orsay', 'musee-orsay', 'museum', 'beaux-arts', 'culturel', 48.859961, 2.326561, 7, 'Esplanade Valéry Giscard d''Estaing', '#c499ff', 'pin', 1, 4.8, 0, 'https://maps.googleapis.com/maps/api/place/photo?maxwidth=1600&photoreference=AcnlKN1gas3991_QGxW_zK-6O_nd94HbFoh10ZNY1GN8vQi9IgKdEqTMV3D0WiHOm--aoWL-4uEptspyTVTwnHsStXE2NFNZoUOupvNetquEecULnvK6RcE5VaN0XBU7sgvBfQvvtB34C8eJXnfC7Jaky3umsAgpGW5cRkmxIaEJX0vtbuJEaYOQ4nYiZDaemsQTq43YJmhaq1HlD0VGMWIXDKi8gY1NWQBBuJ-PedjPvJMUjCjF15t9eDUa_s3Z0e2V6AfnXBzLIWYubLnzIU8V1bcELa3ScbVixx3XcfKItXabiQ-G1tfJ-kalvhuF-5EZ2GonWCnOdfK4J1cN-1cDjXav4myO5P_DjbWQ_jtIV7z3nj1XR6kS_404dnCbsaxCoY23v-itSWUpIhXEH4_3CM0yf7dBOzVDP-X3nwZz2V5sLSrE&key=AIzaSyDpkuHPvH-X8hZrLrpZbyC2Hi39iAfrLKM', NULL, 15, 0, '€', NULL, NULL, NULL, 0, 0, 50, '{"chill":7,"festif":4,"culturel":24}', '{}', '["museum","beaux-arts"]', '{"standard":"","display":"","detailed":""}', '{"reservation_policy":null,"accessibility":false,"wifi":false,"opening_hours_raw":"","action_type":"site","action_url":"","terrace":false,"happy_hour":null}', '{"index_price":15,"avg_budget":16,"is_free":false,"pint_price":0,"cocktail_price":0,"coffee_price":0,"dish_price":0,"menu_items":[]}', '{"hero":"https://maps.googleapis.com/maps/api/place/photo?maxwidth=1600&photoreference=AcnlKN1gas3991_QGxW_zK-6O_nd94HbFoh10ZNY1GN8vQi9IgKdEqTMV3D0WiHOm--aoWL-4uEptspyTVTwnHsStXE2NFNZoUOupvNetquEecULnvK6RcE5VaN0XBU7sgvBfQvvtB34C8eJXnfC7Jaky3umsAgpGW5cRkmxIaEJX0vtbuJEaYOQ4nYiZDaemsQTq43YJmhaq1HlD0VGMWIXDKi8gY1NWQBBuJ-PedjPvJMUjCjF15t9eDUa_s3Z0e2V6AfnXBzLIWYubLnzIU8V1bcELa3ScbVixx3XcfKItXabiQ-G1tfJ-kalvhuF-5EZ2GonWCnOdfK4J1cN-1cDjXav4myO5P_DjbWQ_jtIV7z3nj1XR6kS_404dnCbsaxCoY23v-itSWUpIhXEH4_3CM0yf7dBOzVDP-X3nwZz2V5sLSrE&key=AIzaSyDpkuHPvH-X8hZrLrpZbyC2Hi39iAfrLKM","gallery":[]}', '[]', NULL, '{"insider_tip":"L''entrée est gratuite tous les premiers dimanches du mois.","specials":{"cuisine":[],"drinks":[]}}', 'Installé dans une ancienne gare ferroviaire aux volumes monumentaux, le Musée d''Orsay abrite la plus riche collection au monde de chefs-d''œuvre impressionnistes et post-impressionnistes. Entre les toiles de Monet, Degas, Renoir ou Van Gogh, on déambule sous la grande horloge d''origine avec une émotion toujours intacte. Le dialogue entre l''architecture de fer et de verre et les couleurs vibrantes de l''art du XIXe siècle est unique au monde.', 'L''entrée est gratuite tous les premiers dimanches du mois.', 'À proximité', '[]', '[]', NULL, NULL);
INSERT INTO places_fts VALUES ('poi-147', 'Musée d''Orsay', 'museum', 'beaux-arts', 'Esplanade Valéry Giscard d''Estaing', '', 'Installé dans une ancienne gare ferroviaire aux volumes monumentaux, le Musée d''Orsay abrite la plus riche collection au monde de chefs-d''œuvre impressionnistes et post-impressionnistes. Entre les toiles de Monet, Degas, Renoir ou Van Gogh, on déambule sous la grande horloge d''origine avec une émotion toujours intacte. Le dialogue entre l''architecture de fer et de verre et les couleurs vibrantes de l''art du XIXe siècle est unique au monde.');
INSERT INTO places VALUES ('poi-028', 'Parc Monceau', 'parc-monceau', 'parc', 'jardin-romantique', 'chill', 48.879683, 2.308955, 8, '35 Boulevard de Courcelles', '#8ccaf7', 'pin', 1, 4.6, 0, '/images/parc-monceau.jpg', NULL, 0, 1, '€', 0, 0, 0, 0, 0, 50, '{"chill":24.8,"festif":2,"culturel":7.5}', '{}', '["parc","jardin-romantique"]', '{"standard":"","display":"","detailed":""}', '{"reservation_policy":null,"accessibility":false,"wifi":false,"opening_hours_raw":"","action_type":"site","action_url":"","terrace":false,"happy_hour":null}', '{"avg_budget":2,"is_free":true,"pint_price":0,"cocktail_price":0,"coffee_price":0,"dish_price":0,"menu_items":[]}', '{"hero":"/images/parc-monceau.jpg","gallery":[]}', '[]', NULL, '{"insider_tip":"L''adresse préférée des locaux, loin des foules habituelles.","specials":{"cuisine":[],"drinks":[]}}', 'Le parc le plus élégant et le plus ''proustien'' de Paris. Entouré d''hôtels particuliers somptueux, on y accède par des grilles dorées. C''est un jardin de folies architecturales : une pyramide égyptienne, une colonnade corinthienne au bord d''un bassin (la Naumachie), un pont vénitien... C''est le jardin des enfants chics du 8ème et des nounous en uniforme. Idéal pour lire un livre sur un banc en se prenant pour un héros romantique.', 'L''adresse préférée des locaux, loin des foules habituelles.', 'Monceau', '[2]', '[]', NULL, NULL);
INSERT INTO places_fts VALUES ('poi-028', 'Parc Monceau', 'parc', 'jardin-romantique', '35 Boulevard de Courcelles', '', 'Le parc le plus élégant et le plus ''proustien'' de Paris. Entouré d''hôtels particuliers somptueux, on y accède par des grilles dorées. C''est un jardin de folies architecturales : une pyramide égyptienne, une colonnade corinthienne au bord d''un bassin (la Naumachie), un pont vénitien... C''est le jardin des enfants chics du 8ème et des nounous en uniforme. Idéal pour lire un livre sur un banc en se prenant pour un héros romantique.');
INSERT INTO places VALUES ('poi-176', 'Buddy Buddy', 'buddy-buddy-paris', 'café', 'specialty-coffee', 'chill', 48.871832, 2.363402, 8, '15 Rue de Marseille', '#8ccaf7', 'pin', 1, 4.6, 0, 'https://maps.googleapis.com/maps/api/place/photo?maxwidth=1600&photoreference=AcnlKN1RfW-OxkEn_roRx9Bb43NP0XipXDbWVpq1t-jDkLa4E0tX6olf7eq3iBPsYRBFrW_GEQY-870pTkyxhG8dpDjQu3WlO62McmqvIcWWJIN16J1kfyII1EfNnLaK7JnIkENnX2pbXBbf8Wxe99NyoZFLjjXDKMopO0yeapi8ZtxBFsBTU-hPvKnYZYC-NJgNHqIi9ggjwIau-ZFb4TKu8ZUHp9NrQbMx7BYiz3G1mKXELXV3PMwnk94YGWdpD3YvTykM4JmfuOmKbXJ7L2rd2JlPuYKt1seXZHssKV0L8PZJcQ&key=AIzaSyDpkuHPvH-X8hZrLrpZbyC2Hi39iAfrLKM', NULL, 4.5, 0, '€', NULL, NULL, NULL, 4.5, 0, 50, '{"chill":23,"festif":4,"culturel":5}', '{}', '["café","specialty-coffee"]', '{"standard":"","display":"","detailed":""}', '{"reservation_policy":null,"accessibility":false,"wifi":false,"opening_hours_raw":"","action_type":"site","action_url":"","terrace":false,"happy_hour":null}', '{"avg_budget":14,"is_free":false,"pint_price":0,"cocktail_price":0,"coffee_price":4.5,"dish_price":0,"menu_items":[]}', '{"hero":"https://maps.googleapis.com/maps/api/place/photo?maxwidth=1600&photoreference=AcnlKN1RfW-OxkEn_roRx9Bb43NP0XipXDbWVpq1t-jDkLa4E0tX6olf7eq3iBPsYRBFrW_GEQY-870pTkyxhG8dpDjQu3WlO62McmqvIcWWJIN16J1kfyII1EfNnLaK7JnIkENnX2pbXBbf8Wxe99NyoZFLjjXDKMopO0yeapi8ZtxBFsBTU-hPvKnYZYC-NJgNHqIi9ggjwIau-ZFb4TKu8ZUHp9NrQbMx7BYiz3G1mKXELXV3PMwnk94YGWdpD3YvTykM4JmfuOmKbXJ7L2rd2JlPuYKt1seXZHssKV0L8PZJcQ&key=AIzaSyDpkuHPvH-X8hZrLrpZbyC2Hi39iAfrLKM","gallery":[]}', '[]', NULL, '{"insider_tip":"L''adresse préférée des locaux, loin des foules habituelles.","specials":{"cuisine":[],"drinks":[]}}', 'Le premier ''nut butter café'' de France est un spot minimaliste et design qui révolutionne l''heure du café. Buddy Buddy propose des créations à base de leurs propres beurres de noisettes, cacahuètes et amandes artisanaux, torréfiés sur place. Latte au beurre de noisette, tartines gourmandes et pâtisseries végétales composent une carte saine et terriblement addictive. Un lieu qui respire la précision bruxelloise et la gourmandise moderne au cœur du chic 8ème arrondissement.', 'L''adresse préférée des locaux, loin des foules habituelles.', 'À proximité', '[]', '[]', NULL, NULL);
INSERT INTO places_fts VALUES ('poi-176', 'Buddy Buddy', 'café', 'specialty-coffee', '15 Rue de Marseille', '', 'Le premier ''nut butter café'' de France est un spot minimaliste et design qui révolutionne l''heure du café. Buddy Buddy propose des créations à base de leurs propres beurres de noisettes, cacahuètes et amandes artisanaux, torréfiés sur place. Latte au beurre de noisette, tartines gourmandes et pâtisseries végétales composent une carte saine et terriblement addictive. Un lieu qui respire la précision bruxelloise et la gourmandise moderne au cœur du chic 8ème arrondissement.');
