cials":{"cuisine":["Français","Viande","Aubrac"],"drinks":["Grands Vins","Vieux Rhums"],"must_eat":"Cuisine de l''Aubrac. L''onglet de bœuf ou le traditionnel Aligot filant servi à table.","expert_catchline":"Le temple de la viande aveyronnaise ouvert quand tout le monde dort."}}', 'Véritable institution située à deux pas des Champs-Élysées, La Maison de l''Aubrac est le sanctuaire de la noda rouge. Ici, la viande provient directement de l''élevage familial en Aveyron, garantissant une traçabilité et une qualité exceptionnelles. Le cadre est élégant mais sans chichis, avec une cave impressionnante de plus de 800 références. C''est l''un des rares endroits de la capitale où l''on peut déguster un aligot filant à 4h du matin.', '• Pour les vrais amateurs, l''Aligot est un passage obligé : il est servi avec une générosité typique du terroir.
INSERT INTO places_fts VALUES ('poi-maison-de-l-aubrac', 'La Maison de l''Aubrac', 'restaurant', 'viande aubrac steakhouse institution terrasse ouvert-tard', '37 Rue Marbeuf, 75008 Paris', '', 'Véritable institution située à deux pas des Champs-Élysées, La Maison de l''Aubrac est le sanctuaire de la noda rouge. Ici, la viande provient directement de l''élevage familial en Aveyron, garantissant une traçabilité et une qualité exceptionnelles. Le cadre est élégant mais sans chichis, avec une cave impressionnante de plus de 800 références. C''est l''un des rares endroits de la capitale où l''on peut déguster un aligot filant à 4h du matin.');
INSERT INTO places VALUES ('poi-175', 'Musée Jacquemart-André', 'musee-jacquemart-andre', 'museum', 'beaux-arts', 'culturel', 48.875553, 2.310422, 8, '158 Bd Haussmann', '#c499ff', 'pin', 1, 4.5, 0, 'https://maps.googleapis.com/maps/api/place/photo?maxwidth=1600&photoreference=AcnlKN2BJXFVav7FXCILgBH0mhp5KKNDyUiulihk32XvnjZqYFnSeY7YUhFO8Oud_oRQJxBXJY92eOwSINiZphtZaqhxrAsnyiUblFNRwSEDv_xpzuEcOoMTOhDb_ye0EiQ2nFGP9zgPMsrPKHBKEtoESxN7Yotsu0PctIGAVgLNMC4gVObNuPQMXxyoESBVLklmZJVp-U0Pq80MVEx1HpsJsPiv_AJL9eb_k4VY43YoNGkqVtW_BMSA9Mxr3BxgkvJaUnmEO54aBLc6IM3IOcD3wfZHPq_aoms3cjFPls93kxf_riWf5JHW3Y_dcZaUvrvdHQ0tTWLswrwI-8uUkpcJLepK5J_Vhfl3K4hyfTCGGA3MVs1bpin61xVMB0F8nmmleejFArdj__vL3nmSVs0x5N1cfJobKL_xYzJShDgBZ8c&key=AIzaSyDpkuHPvH-X8hZrLrpZbyC2Hi39iAfrLKM', NULL, 15, 0, '€', NULL, NULL, NULL, 0, 0, 50, '{"chill":6,"festif":4,"culturel":24}', '{}', '["museum","beaux-arts"]', '{"standard":"","display":"","detailed":""}', '{"reservation_policy":null,"accessibility":false,"wifi":false,"opening_hours_raw":"","action_type":"site","action_url":"","terrace":false,"happy_hour":null}', '{"index_price":15,"avg_budget":17,"is_free":false,"pint_price":0,"cocktail_price":0,"coffee_price":0,"dish_price":0,"menu_items":[]}', '{"hero":"https://maps.googleapis.com/maps/api/place/photo?maxwidth=1600&photoreference=AcnlKN2BJXFVav7FXCILgBH0mhp5KKNDyUiulihk32XvnjZqYFnSeY7YUhFO8Oud_oRQJxBXJY92eOwSINiZphtZaqhxrAsnyiUblFNRwSEDv_xpzuEcOoMTOhDb_ye0EiQ2nFGP9zgPMsrPKHBKEtoESxN7Yotsu0PctIGAVgLNMC4gVObNuPQMXxyoESBVLklmZJVp-U0Pq80MVEx1HpsJsPiv_AJL9eb_k4VY43YoNGkqVtW_BMSA9Mxr3BxgkvJaUnmEO54aBLc6IM3IOcD3wfZHPq_aoms3cjFPls93kxf_riWf5JHW3Y_dcZaUvrvdHQ0tTWLswrwI-8uUkpcJLepK5J_Vhfl3K4hyfTCGGA3MVs1bpin61xVMB0F8nmmleejFArdj__vL3nmSVs0x5N1cfJobKL_xYzJShDgBZ8c&key=AIzaSyDpkuHPvH-X8hZrLrpZbyC2Hi39iAfrLKM","gallery":[]}', '[]', NULL, '{"insider_tip":"L''entrée est gratuite tous les premiers dimanches du mois.","specials":{"cuisine":[],"drinks":[]}}', 'C''est la plus belle collection privée de chefs-d''œuvre à Paris, logée dans l''hôtel particulier d''un couple de collectionneurs du XIXe. Entre peinture italienne de la Renaissance et école flamande, on déambule sous les plafonds peints de Tiepolo. Le clou du spectacle est sans doute le salon de thé, situé dans l''ancienne salle à manger, considéré comme l''un des plus raffinés de la capitale. Une expérience de luxe et de culture d''une élégance absolue sur le boulevard Haussmann.', 'L''entrée est gratuite tous les premiers dimanches du mois.', 'À proximité', '[]', '[]', NULL, NULL);
INSERT INTO places_fts VALUES ('poi-175', 'Musée Jacquemart-André', 'museum', 'beaux-arts', '158 Bd Haussmann', '', 'C''est la plus belle collection privée de chefs-d''œuvre à Paris, logée dans l''hôtel particulier d''un couple de collectionneurs du XIXe. Entre peinture italienne de la Renaissance et école flamande, on déambule sous les plafonds peints de Tiepolo. Le clou du spectacle est sans doute le salon de thé, situé dans l''ancienne salle à manger, considéré comme l''un des plus raffinés de la capitale. Une expérience de luxe et de culture d''une élégance absolue sur le boulevard Haussmann.');
INSERT INTO places VALUES ('poi-181', 'Musée Nissim de Camondo', 'musee-nissim-camondo', 'museum', 'arts-decoratifs', 'culturel', 48.879058, 2.312465, 8, '63 Rue de Monceau', '#c499ff', 'pin', 1, 4.7, 0, 'https://maps.googleapis.com/maps/api/place/photo?maxwidth=1600&photoreference=AcnlKN0B5s5DNC74KbX11Y2RKuSv2ZB9fjpYgehObRMy087xyLO4gz0KeKx6r4pfJiwf7aFD2RVJgCTyYX8ndjxgByKJKDXQbbzBupqVg6Ru0jhRc7VMnHeU9xqn3N_-E-ugnFZknMas728UqMA5QGJnAZIRQPIHTazq-0SjrUr39DcJCy_LldG97J5WUtDOADByBywoV0xZkRcjz-3hsH3OSyEfDTQZ8mwreXCzGd75lCGAhToW1jd88XnaqiI_bQG6o8uWPeo9D2qc5qlxtOrty_s1MVvvXhAsAR8AB2BGHHMcAw&key=AIzaSyDpkuHPvH-X8hZrLrpZbyC2Hi39iAfrLKM', NULL, 15, 0, '€', NULL, NULL, NULL, 0, 0, 50, '{"chill":6,"festif":4,"culturel":24}', '{}', '["museum","arts-decoratifs"]', '{"standard":"","display":"","detailed":""}', '{"reservation_policy":null,"accessibility":false,"wifi":false,"opening_hours_raw":"","action_type":"site","action_url":"","terrace":false,"happy_hour":null}', '{"index_price":15,"avg_budget":12,"is_free":false,"pint_price":0,"cocktail_price":0,"coffee_price":0,"dish_price":0,"menu_items":[]}', '{"hero":"https://maps.googleapis.com/maps/api/place/photo?maxwidth=1600&photoreference=AcnlKN0B5s5DNC74KbX11Y2RKuSv2ZB9fjpYgehObRMy087xyLO4gz0KeKx6r4pfJiwf7aFD2RVJgCTyYX8ndjxgByKJKDXQbbzBupqVg6Ru0jhRc7VMnHeU9xqn3N_-E-ugnFZknMas728UqMA5QGJnAZIRQPIHTazq-0SjrUr39DcJCy_LldG97J5WUtDOADByBywoV0xZkRcjz-3hsH3OSyEfDTQZ8mwreXCzGd75lCGAhToW1jd88XnaqiI_bQG6o8uWPeo9D2qc5qlxtOrty_s1MVvvXhAsAR8AB2BGHHMcAw&key=AIzaSyDpkuHPvH-X8hZrLrpZbyC2Hi39iAfrLKM","gallery":[]}', '[]', NULL, '{"insider_tip":"L''entrée est gratuite tous les premiers dimanches du mois.","specials":{"cuisine":[],"drinks":[]}}', 'En bordure du parc Monceau, ce musée raconte la tragédie extraordinaire de la famille de Camondo. Dans cet hôtel particulier figé en 1910, chaque meuble du XVIIIe, chaque porcelaine est un chef-d œuvre. On y découvre l intimité d une dynastie de banquiers passionnés d art français, dont l''histoire fut brutalement stoppée par la déportation. Un lieu d''une beauté mélancolique et d''un luxe absolu, offrant un témoignage poignant sur l''élégance disparue de la Belle Époque.', 'L''entrée est gratuite tous les premiers dimanches du mois.', 'À proximité', '[]', '[]', NULL, NULL);
INSERT INTO places_fts VALUES ('poi-181', 'Musée Nissim de Camondo', 'museum', 'arts-decoratifs', '63 Rue de Monceau', '', 'En bordure du parc Monceau, ce musée raconte la tragédie extraordinaire de la famille de Camondo. Dans cet hôtel particulier figé en 1910, chaque meuble du XVIIIe, chaque porcelaine est un chef-d œuvre. On y découvre l intimité d une dynastie de banquiers passionnés d art français, dont l''histoire fut brutalement stoppée par la déportation. Un lieu d''une beauté mélancolique et d''un luxe absolu, offrant un témoignage poignant sur l''élégance disparue de la Belle Époque.');
