nal.
INSERT INTO places_fts VALUES ('poi-zhao-canal', 'La Taverne de Zhao', 'restaurant', 'chinois noodles biang-biang authentique chill', '49 Rue des Vinaigriers, 75010 Paris, France', '', 'C''est ici que tout a commencé en 2011. La Taverne de Zhao Canal Saint-Martin est le berceau parisien des nouilles Biang Biang. Avec ses tables en bois et son ambiance factory ultra-chill, c''est l''adresse parfaite pour une pause authentique loin de l''agitation du boulevard.');
