NZz7amPHm-iIiPMAI10x56cvdj7mlL9cdr4CckdHoJhQDPAxSdQfY_kg4nQL-ME2RnjQm0fV0QzC02bcTTbNGUTLznws98ngrJN3a6tVqgJqWjuasFl8CgAOWi8jicBklgqvaznHN0oyjkhHuaxFmDYY6abc2RNt0rrqc90nJIgZbM89EApXgUSiwqmpxC_gSLA38JeA3mIEKO3j04M35ks38Ib6zfg9aaFBzfz4Da4aVye2YfabwYJDEusphGk4X51C9AQRdppHq1VSAe50_lB-kRP90PfmizD3QX76yP6DRpkH9uITify_DMZRNC6CeBZ9Atq-5Hr1NKhYzxYP5f4ofxXAcm57JLOUuCyOib9Xn7aJ7pL-V7FNJd8vJ7skHTAIEZc18efWBEXzyuG5HddEUKH8MQ7","AU_ZVEEhsNOQKIuO_NjIrZ7-0ISU5VFJLgIEhAyyuZOiTKY0VLiEWsSM_euYN5URSsEc2jH1dLAMVvm4Ht5C36YV4_q9l_FxOrXFhDc7xGc0fUuraA7ECVfXhBsB_sR1NP1wmuaUkt-Mybz48MXpcVHBnFfq2iS69VmsYQoRc9aC9odr5SaUMFJYYaiCjKmXAyS7sKTGygEzBQ2VgSCaLqxO-d58hQ3Xahl6NFdiNsKXZxPeabyLs3jaoKYR73qO3esn66TKEBxIIacLrjysRRwxOVlGRonIm1Qd9gJ3PlzJ8P9u-A"]', NULL, '{"insider_tip":"• Idéal pour les voyageurs pressés : le service est l''un des plus rapides de Paris.\n• La salle est un peu plus ''aérée'' que celle des Grands Boulevards, ce qui rend l''expérience légèrement moins bruyante.\n• Demandez un ''quart de bouillon rouge'' pour accompagner votre choucroute, une tradition de l''adresse.","specials":{"cuisine":["Française","Bouillon","Populaire"],"drinks":["Bouillon Rouge","Café"],"must_eat":"Cuisine française. Œufs Mayonnaise & Choucroute alsacienne"}}', 'Dernier né de la famille ouvert en 2019 juste en face de la Gare de l''Est, ce bouillon perpétue la tradition du ''bien manger pour pas cher''. Dans un cadre qui semble avoir toujours existé, on y retrouve le ballet incessant des serveurs et les plats qui ont fait la renommée de l''enseigne. L''escale parfaite avant de prendre un train ou après une balade sur les quais du canal.', '• Idéal pour les voyageurs pressés : le service est l''un des plus rapides de Paris.
INSERT INTO places_fts VALUES ('poi-bouillon-chartier-gare-de-l-est', 'Bouillon Chartier Gare de l''Est', 'restaurant', 'français bouillon traditionnel voyage belle-epoque', '5 Rue du 8 Mai 1945, 75010 Paris, France', '', 'Dernier né de la famille ouvert en 2019 juste en face de la Gare de l''Est, ce bouillon perpétue la tradition du ''bien manger pour pas cher''. Dans un cadre qui semble avoir toujours existé, on y retrouve le ballet incessant des serveurs et les plats qui ont fait la renommée de l''enseigne. L''escale parfaite avant de prendre un train ou après une balade sur les quais du canal.');
INSERT INTO places VALUES ('poi-013', 'Café A', 'cafe-a', 'café', 'cafe-jardin', 'chill', 48.875386, 2.360012, 10, '148 Rue du Faubourg Saint-Martin', '#8ccaf7', 'pin', 1, 4.2, 0, 'https://upload.wikimedia.org/wikipedia/commons/c/c9/Jardin_Villemin_-_Couvent_des_R%C3%A9collets.jpg', NULL, 3.5, 0, '€', NULL, NULL, NULL, 3.5, 16, 50, '{"chill":24,"festif":4,"culturel":7.5}', '{}', '["café","cafe-jardin"]', '{"standard":"","display":"","detailed":""}', '{"reservation_policy":null,"accessibility":false,"wifi":false,"opening_hours_raw":"","action_type":"site","action_url":"","terrace":false,"happy_hour":null}', '{"avg_budget":20,"is_free":false,"pint_price":0,"cocktail_price":0,"coffee_price":3.5,"dish_price":16,"last_updated":"2025-01-15","menu_items":[]}', '{"hero":"https://upload.wikimedia.org/wikipedia/commons/c/c9/Jardin_Villemin_-_Couvent_des_R%C3%A9collets.jpg","gallery":[]}', '[]', NULL, '{"insider_tip":"L''adresse préférée des locaux, loin des foules habituelles.","specials":{"cuisine":[],"drinks":[]}}', 'Installé dans l''ancien couvent des Récollets (actuelle Maison de l''Architecture), près de la Gare de l''Est, le Café A possède l''une des plus belles cours intérieures secrètes de Paris. On boit un verre sous les arcades ou allongé dans des transats sur le gravier blanc, à l''ombre de vieux arbres. C''est calme, vaste, et inattendu dans ce quartier dense. Un havre de paix architectural parfait pour les beaux jours.', 'L''adresse préférée des locaux, loin des foules habituelles.', 'Gare de l''Est', '[4,5,7]', '[]', NULL, NULL);
INSERT INTO places_fts VALUES ('poi-013', 'Café A', 'café', 'cafe-jardin', '148 Rue du Faubourg Saint-Martin', '', 'Installé dans l''ancien couvent des Récollets (actuelle Maison de l''Architecture), près de la Gare de l''Est, le Café A possède l''une des plus belles cours intérieures secrètes de Paris. On boit un verre sous les arcades ou allongé dans des transats sur le gravier blanc, à l''ombre de vieux arbres. C''est calme, vaste, et inattendu dans ce quartier dense. Un havre de paix architectural parfait pour les beaux jours.');
