 un indispensable de la maison en hiver.
INSERT INTO places_fts VALUES ('poi-clown-bar', 'Clown Bar', 'restaurant', 'bistronomie historique restaurant', '114 Rue Amelot', '', 'L''ancien bar attenant au Cirque d''Hiver, classé aux monuments historiques (faillence Belle Époque de clowns), est devenu l''une des tables bistronomiques les plus prisées et avant-gardistes de la capitale.');
