INSERT INTO places_fts VALUES ('poi-osteria-goto', 'Osteria Gòto', 'restaurant', 'italian venetian osteria natural wine', '151 Boulevard Voltaire', '', 'Une immersion vénitienne brute sur le boulevard Voltaire. Gòto célèbre les ''Cicchetti'' (tapas italiens) et les vins naturels dans une ambiance d''osteria authentique. Ici, le produit prime, servi sans chichi mais avec une science des terroirs italiens impeccable.');
