K9zq4hUM8jmVl58QdFDs7RbvZMrOtL76CYckQQMWAKPX2iXgRG-jxOUnkPAc77_qOD6W0H4e9h7WSUsLfIMSLU9X_oclQQud7_AshFeflsXyCeSF5fg0yj2aspLf2p6_ktEkGAXDrmZL2sEJ29X7OFnVLg2jyaSRVlanprPav8fT6RWYeF05i007Kv8_dQn4nXyhlpqYnIrIGtAjWKf3jJxW_y6WIb_d6j7cj_wuOYfmny1ZhNdsUo2D42fO16_d8vtW2Gr0bck2BNgldyYDqnp18vW4Eh6kqX3t7hqHkoTjRh0e&key=AIzaSyDpkuHPvH-X8hZrLrpZbyC2Hi39iAfrLKM"]', NULL, '{"insider_tip":"Le Cabillaud Tom Cakod est le plat qui définit le lieu : un équilibre parfait entre l''onctuosité de la coco et le peps du galanga. Réservez une table près de la cuisine pour voir le ballet du chef.","specials":{"cuisine":["Fusion Franco-Asiatique","Bistronomie technique","Dressages artistiques"],"drinks":["Sélection de vins nature","Thés asiatiques premium"],"must_eat":"Le Cabillaud Tom Cakod à l''émulsion de coco.","must_drink":"Un vin blanc minéral de la Loire pour accompagner les Saint-Jacques."},"expert_catchline":"L''Asie et la France en parfaite harmonie rue de Charonne."}', 'Une prouesse de fusion par le chef Hung Luan Nguyen. Confluence mêle la finesse de la gastronomie française aux saveurs vibrantes de l''Asie (Vietnam, Thaïlande). Le dressage est aussi précis que les goûts sont justes.', 'Le Cabillaud Tom Cakod est le plat qui définit le lieu : un équilibre parfait entre l''onctuosité de la coco et le peps du galanga. Réservez une table près de la cuisine pour voir le ballet du chef.', 'Charonne', '[9]', '[]', 'ChIJ-8eXUxtz5kcR8qhr1b31dXk', NULL);
INSERT INTO places_fts VALUES ('poi-confluence', 'Confluence', 'restaurant', 'bistronomie fusion franco-asiatique gastronomique', '79 Rue de Charonne', '', 'Une prouesse de fusion par le chef Hung Luan Nguyen. Confluence mêle la finesse de la gastronomie française aux saveurs vibrantes de l''Asie (Vietnam, Thaïlande). Le dressage est aussi précis que les goûts sont justes.');
INSERT INTO places VALUES ('poi-dersou', 'Dersou', 'dersou', 'restaurant', 'Bistronomique, Fusion, Cocktail Pairing, Vins Natures', 'chill', 48.8524, 2.3789, 11, '21 Rue de la Forge Royale, 75011 Paris', '#8ccaf7', 'pin', 1, 4.5, 0, 'https://static.wixstatic.com/media/dersou-paris-interior.jpg', NULL, 37, NULL, '€', NULL, NULL, NULL, NULL, 37, 50, '{"chill":70,"festif":30,"culturel":50}', '{}', '["restaurant","Bistronomique","Fusion","Cocktail Pairing","Vins Natures"]', '{"standard":"Mar-Sam: 12:00–14:30, 19:30–23:00\nDim-Lun: Fermé","display":"Mar-Sam: 12:00–14:30, 19:30–23:00","detailed":"Mar-Sam: 12:00–14:30, 19:30–23:00\nDim-Lun: Fermé"}', '{"reservation_policy":"resa_conseillee","accessibility":true,"wifi":false,"terrace":false,"vegan_friendly":false,"opening_hours_raw":"Mar-Sam: 12:00–14:30, 19:30–23:00\nDim-Lun: Fermé","main_action":{"type":"site","url":"http://www.dersouparis.com/","label":"RÉSERVER"},"happy_hour":null}', '{"avg_budget":60,"index_price":33,"dish_price":37,"menu_type":"fixed","last_updated":"2026-03-08","menu_items":[{"category":"Menus Dégustation & Lunch","items":[{"name":"Menu Dîner 6 étapes","price":"95.00€","description":"L''expérience signature du chef avec pairing cocktail."},{"name":"Menu Dîner 7 étapes","price":"110.00€","description":"L''immersion totale, service prolongé."},{"name":"Lunch Menu (3 étapes)","price":"28.00€","description":"Servi en semaine, retour de marché."},{"name":"Lunch Menu (5 étapes)","price":"45.00€","description":"La version gastronomique du déjeuner."},{"name":"Accord Cocktails (6 verres)","price":"40.00€"}]},{"category":"Petites Assiettes (Lunch / A la Carte)","items":[{"name":"Huître d''Arcachon N2, crème crue & citron","price":"3.50€"},{"name":"Sardines de Bolinche marinées, brioche","price":"8.50€"},{"name":"Pommes Dauphine au Brillat Savarin","price":"7.50€"},{"name":"Tartelette aux Chanterelles & ail des ours","price":"15.00€"},{"name":"Sashimi de Sériole, sauce ponzu","price":"19.00€"},{"name":"Carpaccio de Bœuf Wagyu, sésame grillé","price":"22.00€"},{"name":"Tataki de Thon Rouge, vinaigrette soja-gingembre","price":"18.00€"},{"name":"Croquette de Porc Noir, moutarde au miel","price":"9.00€"},{"name":"Asperges Vertes Grillées, parmesan & zestes","price":"14.00€"},{"name":"Pickles Maison de Saison","price":"5.00€"},{"name":"Terrine de Campagne au poivre long","price":"11.00€"}]},{"category":"Les Plats","items":[{"name":"Filet de Lotte à la grenobloise","price":"33.00€","description":"Chanterelles jaunes et beurre noisette."},{"name":"Turbot au BBQ, bok choy, sauce matelote","price":"38.00€"},{"name":"Suprême de Pintade rôtie, jus corsé","price":"37.00€"},{"name":"Flatbread Agneau de lait BBQ","price":"18.00€"},{"name":"Dashi Curry Vegetarien, légumes racines","price":"24.00€"},{"name":"Calamar à la Plancha, encre et chorizo","price":"28.00€"},{"name":"Entrecôte Maturée (300g), sauce béarnaise Dersou","price":"42.00€"},{"name":"Riz sauté au Kimchi & œuf bio","price":"16.00€"}]},{"category":"Douceurs & Fromages","items":[{"name":"Assiette de trois fromages affinés","price":"15.00€"},{"name":"Tarte poire & amande","price":"13.00€"},{"name":"Glace Orange Sanguine, bavaroise fromage blanc","price":"12.00€"},{"name":"Ganache Chocolat Noir & Sel de Mer","price":"11.00€"},{"name":"Sorbet Maison (Parfum du jour)","price":"6.00€"}]},{"category":"Signature Cocktails","items":[{"name":"Dersou Mule (Vodka, Ginger, Lime)","price":"14.00€"},{"name":"Old Fashioned Japonais (Nikka Whisky)","price":"16.00€"},{"name":"Gin & Shiso Tonic","price":"14.00€"},{"name":"Pisco Sour à la Cardamome","price":"15.00€"},{"name":"Mescal & Chili Smokey Drink","price":"16.00€"},{"name":"Mocktail Virgin Yuzu","price":"9.00€"}]}]}', '{"hero":"https://static.wixstatic.com/media/dersou-paris-interior.jpg","gallery":["https://lh3.googleusercontent.com/p/AF1QipN_XQ_XQ_XQ_XQ_XQ_XQ_XQ_XQ_XQ_XQ_XQ_XQ=s1360-w1360-h1020"]}', '["https://lh3.googleusercontent.com/p/AF1QipN_XQ_XQ_XQ_XQ_XQ_XQ_XQ_XQ_XQ_XQ_XQ_XQ=s1360-w1360-h1020"]', NULL, '{"insider_tip":"• L''expérience complète se vit au dîner avec le menu dégustation et l''accord cocktail : c''est l''essence même du lieu.\n• Le midi, la carte plus accessible permet de goûter à la précision du chef sans se ruiner.\n• Installez-vous au comptoir pour voir la brigade à l''œuvre et échanger avec les barmans sur les créations du moment.\n• La sélection de vins naturels est également très pointue pour ceux qui boudent les cocktails.","specials":{"cuisine":["Fusion","Bistronomique","Sashimi Sériole"],"drinks":["Cocktails Signature","Vins Natures","Pairing Alcoolisé"],"must_eat":"Le menu dégustation 6 étapes et les sardines sur brioche."},"expert_catchline":"L''art du pairing fusion : une cuisine d''auteur percutante accompagnée de cocktails haute couture."}', 'Dersou est un ovni gastronomique situé entre Bastille et Charonne. Pionnier du pairing ''plat-cocktail'', le restaurant propose une cuisine d''auteur brute et sophistiquée, où les influences asiatiques et européennes s''entrechoquent avec brio. Le décor industriel avec ses murs grattés et son grand comptoir en métal entoure une cuisine ouverte bouillonnante d''énergie.', '• L''expérience complète se vit au dîner avec le menu dégustation et l''accord cocktail : c''est l''essence même du lieu.
INSERT INTO places_fts VALUES ('poi-dersou', 'Dersou', 'restaurant', 'Bistronomique Fusion Cocktail Pairing Vins Natures', '21 Rue de la Forge Royale, 75011 Paris', '', 'Dersou est un ovni gastronomique situé entre Bastille et Charonne. Pionnier du pairing ''plat-cocktail'', le restaurant propose une cuisine d''auteur brute et sophistiquée, où les influences asiatiques et européennes s''entrechoquent avec brio. Le décor industriel avec ses murs grattés et son grand comptoir en métal entoure une cuisine ouverte bouillonnante d''énergie.');
