€"},{"name":"Focaccia au Lamb Pulled","price":"14.00€"},{"name":"Tartine Avocat & Gravlax","price":"15.50€"}]},{"category":"Sweets & Pastries","items":[{"name":"Pancakes Fleur d''Oranger","price":"12.00€","description":"Maple cream et ricotta au citron."},{"name":"Cinnamon Roll (Maison)","price":"5.50€"},{"name":"Carrot Cake & Glaçage","price":"6.50€"},{"name":"Apple Crumble Tiède","price":"7.50€"},{"name":"Tarte Pécan & Caramel","price":"8.00€"},{"name":"Cookies Chocolat & Fleur de Sel","price":"4.00€"},{"name":"Biscuit Artisanal","price":"3.50€"}]},{"category":"Specialty Coffee & Tea (Hot)","items":[{"name":"Espresso (Terroir)","price":"2.50€"},{"name":"Cappuccino Onctueux","price":"5.00€"},{"name":"Flat White","price":"5.00€"},{"name":"Matcha Latte (Premium)","price":"6.00€"},{"name":"Chai Latte Maison","price":"5.50€"},{"name":"Latte de Saison","price":"5.50€"},{"name":"Thé Earl Grey","price":"5.00€"},{"name":"Thé Genmaïcha (Vert)","price":"5.00€"},{"name":"Thé au Jasmin","price":"5.00€"},{"name":"Dirty Chai (Espresso shot)","price":"6.50€"}]},{"category":"Cold Drinks & Juices","items":[{"name":"Fresh Carrot & Ginger Juice","price":"5.50€"},{"name":"Fresh Orange Juice","price":"5.00€"},{"name":"Iced Latte","price":"5.50€"},{"name":"Cold Brew (Seasonal)","price":"6.00€"},{"name":"Citronnade Maison","price":"5.00€"}]},{"category":"Alcohol & Brunch Cocktails","items":[{"name":"Bloody Méricourt","price":"11.00€"},{"name":"Mimosa (Premium Bubbles)","price":"9.50€"},{"name":"Bière Artisanale (Pression)","price":"7.00€"},{"name":"Verre de Vin Blanc","price":"7.50€"},{"name":"Verre de Vin Naturel Rouge","price":"8.00€"}]}]}', '{"hero":"https://lh3.googleusercontent.com/p/AF1QipN_XQ_XQ_XQ_XQ_XQ_XQ_XQ_XQ_XQ_XQ_XQ_XQ=s1360-w1360-h1020","gallery":["https://lh3.googleusercontent.com/p/AF1QipN_XQ_XQ_XQ_XQ_XQ_XQ_XQ_XQ_XQ_XQ_XQ_XQ=s1360-w1360-h1020"]}', '["https://lh3.googleusercontent.com/p/AF1QipN_XQ_XQ_XQ_XQ_XQ_XQ_XQ_XQ_XQ_XQ_XQ_XQ=s1360-w1360-h1020"]', NULL, '{"insider_tip":"• La shakshuka est le plat le plus demandé du lieu, et pour cause : elle est excellente.\n• Pas de réservations le weekend, attendez-vous à un peu de file d''attente sur le trottoir.\n• Leur jus vert Kale/Pomme est le refresh parfait pour lancer la journée.\n• Les pancakes à la fleur d''oranger sont d''une légèreté incroyable.","specials":{"cuisine":["Shakshuka","Brunch","Pancakes"],"drinks":["Filter Coffee","Flat White","Green Juice"],"must_eat":"La Shakshuka et le Breakfast Bun."},"expert_catchline":"Le temple du brunch et de la shakshuka dans une ambiance coffee shop australienne."}', 'Le Café Méricourt est le petit frère du célèbre Café Oberkampf. Dans un espace plus vaste et lumineux, il déploie une carte de brunch aux accents méditerranéens et australiens. Les shakshukas y sont légendaires, tout comme le café de spécialité torréfié localement. C''est le spot idéal pour un petit-déjeuner tardif ou un déjeuner relax dans une atmosphère épurée et conviviale.', '• La shakshuka est le plat le plus demandé du lieu, et pour cause : elle est excellente.
INSERT INTO places_fts VALUES ('poi-cafe-mericourt', 'Café Méricourt', 'restaurant', 'Coffee Shop Brunch Australien Méditerranéen', '22 Rue de la Folie Méricourt, 75011 Paris', '', 'Le Café Méricourt est le petit frère du célèbre Café Oberkampf. Dans un espace plus vaste et lumineux, il déploie une carte de brunch aux accents méditerranéens et australiens. Les shakshukas y sont légendaires, tout comme le café de spécialité torréfié localement. C''est le spot idéal pour un petit-déjeuner tardif ou un déjeuner relax dans une atmosphère épurée et conviviale.');
