INSERT INTO places_fts VALUES ('poi-l-homme-bleu', 'L''Homme Bleu', 'restaurant', 'marocain couscous tajine restaurant', '55 Bis Rue Jean-Pierre Timbaud', '', 'L''institution de la rue Jean-Pierre Timbaud. L''Homme Bleu réalise parmi les meilleurs couscous et tajines de tout Paris dans un décor pur jus oriental chaleureux. Des bouillons ultra-parfumés, des semoules fines comme du sable, des viandes parfaitement cuites. Le spot idéal pour un dîner réconfortant ou un repas dominical.');
