tems":[{"name":"Banana Bread toasté (beurre salé)","price":"6.00€"},{"name":"Cookie Chocolat & Tahini","price":"4.50€"},{"name":"Cake Citron Pavot","price":"5.50€"},{"name":"Halloumi grillé (side)","price":"4.50€"},{"name":"Avocat frais (side)","price":"4.00€"}]},{"category":"Specialty Coffee & Drinks","items":[{"name":"Espresso / Allongé","price":"3.00€"},{"name":"Flat White","price":"4.50€"},{"name":"Latte / Cappuccino","price":"5.00€"},{"name":"Matcha Latte","price":"6.00€"},{"name":"Chai Latte Maison","price":"5.50€"},{"name":"Fresh Orange Juice","price":"5.50€"}]}]}', '{"hero":"https://maps.googleapis.com/maps/api/place/photo?maxwidth=1600&photo_reference=ATCDNfWv--jM--jM--jM--jM--jM--jM--jM--jM--jM--jM--jM--jM--jM--jM--jM--jM--jM--jM--jM--jM--jM--jM--jM--jM--jM--jM--jM--jM--jM--jM--jM--jM--jM--jM--jM--jM--jM--jM--jM--jM--jM--jM--jM--jM--jM--jM--jM--jM--jM--jM--jM--jM--jM--jM--jM--jM--jM--jM--jM--jM--jM--jM--jM--jM--jM--jM--jM--jM&key=AIzaSyDpkuHPvH-X8hZrLrpZbyC2Hi39iAfrLKM"}', '[]', NULL, '{"insider_tip":"Le week-end, la file d''attente peut être longue (pas de réservation). Venez à l''ouverture ou en semaine pour savourer votre shakshuka tranquillement au comptoir.","specials":{"cuisine":["Shakshuka","Avocado Toast","Specialty Coffee"],"drinks":["Flat White","Matcha Latte","Chai Maison"],"must_eat":"La Shakshuka, évidemment.","must_drink":"Leur Flat White est l''un des plus maîtrisés du quartier."},"expert_catchline":"Le coffee shop iconique d''Oberkampf : shakshuka parfaite et vibes cosmopolites."}', 'Petit par la taille mais immense par sa réputation, le Café Oberkampf est le temple du ''Lost in Shakshuka'' à Paris. Ce coffee shop de quartier a su s''imposer grâce à une cuisine franche, colorée et des cafés de spécialité sourcés avec soin. L''ambiance est cosmopolite, vibrante et décontractée, idéale pour un réveil en douceur au cœur du 11ème.', 'Le week-end, la file d''attente peut être longue (pas de réservation). Venez à l''ouverture ou en semaine pour savourer votre shakshuka tranquillement au comptoir.', 'Parmentier', '[3]', '[]', 'ChIJW-v--jM--jM--jM--jM--jM--jM', NULL);
INSERT INTO places_fts VALUES ('poi-037', 'Café Oberkampf', 'restaurant', 'coffee-shop brunch breakfast vegetarian-friendly', '3 Rue Neuve Popincourt', '', 'Petit par la taille mais immense par sa réputation, le Café Oberkampf est le temple du ''Lost in Shakshuka'' à Paris. Ce coffee shop de quartier a su s''imposer grâce à une cuisine franche, colorée et des cafés de spécialité sourcés avec soin. L''ambiance est cosmopolite, vibrante et décontractée, idéale pour un réveil en douceur au cœur du 11ème.');
