is_free":false,"pint_price":7,"cocktail_price":10,"wine_glass":6,"coffee_price":2.5,"dish_price":10.5,"smart_tip":"Formule déjeuner 100% bio imbattable dès 10€. Coworking gratuit l''après-midi. Ambiance cantine bio le midi et bar à tapas le soir.","menu_items":[{"category":"Formules Midi (100% Bio)","items":[{"name":"Entrée + Plat bio","price":"10€"},{"name":"Plat + Dessert bio","price":"10€"},{"name":"Formule complète bio (entrée+plat+dessert)","price":"17€"}]},{"category":"Plats à la carte (Cantine)","items":[{"name":"Bol 1 bio végé du jour","price":"10€"},{"name":"Bol protéiné bio","price":"11€"},{"name":"Duo de crudités bio","price":"3€"},{"name":"Plat chaud bio signature","price":"10€"}]},{"category":"Boissons Sans Alcool (Bio)","items":[{"name":"Citronnade maison bio","price":"4€"},{"name":"Jus Pomme-Carotte bio","price":"4€"},{"name":"ChariTea Mate","price":"4,50€"},{"name":"ChariTea Black","price":"4,50€"},{"name":"Café artisanal bio","price":"2,50€"}]},{"category":"Alcools & Cocktails (Bio)","items":[{"name":"Pinte de bière bio (pression)","price":"7€"},{"name":"Breguet Mule (Vodka/Ginger Beer)","price":"10€"},{"name":"Vodka infusée au basilic","price":"9€"},{"name":"Verre de vin nature bio","price":"6€"},{"name":"Bière bio bouteille","price":"6€"}]},{"category":"Desserts","items":[{"name":"Succulent au chocolat","price":"3€"},{"name":"Gâteau végan bio","price":"4€"}]},{"category":"Brunch (Samedi)","items":[{"name":"Formule Bréguet Brunch (Buffet + Œufs)","price":"32€"}]}],"last_updated":"2026-02-28"}', '{"hero":"https://maps.googleapis.com/maps/api/place/photo?maxwidth=1600&photo_reference=ATCDNfU-CpG6Bdfvop3ojLEvO-HTdIlvT6kldXoW2psUeEVXjYnacod7rbVSjFrboqGDFvMQcCxgkkcuaJucvhrGMAXDAQylzjuwjpHwMrhuAOWuuFsIQtF7vOn-4j30cufa9u910k4caJm8nx7lTLiT39NZapdCP7HcqNc1StAl6XiuOGaTO6Y6L6NJpNyO8Xgh-Fxh4RQ5yWMqbX6ccMagbNehNgHa7F1ikbvwP2LsPGs3jUEBlOhpYgi71qNDPJ6sgJ8gufPfYp1dZXGpZXrDEQOG7FLvEGnlssgSVtbpH3sRmsFz3SdsVnjKK6fLJys91ep_WEZpbd-LGn7zF7rXvtD24le3Qd_7fxPIj9j-bG2D9sUW9Xcpqw9lxkJOzH0GvEmTkDEbCM1WOn29O2KE8Pv7hNg88XrPUDGPau5y8BfV3MNm5t6u9831PBypfAh26Y7vuD7D0GRfCvaAdQVPx9R3rKuDGaOi_Jv5HgaN0zg-JxIt7ZicroB6cHFibhpgp2QVqhxPQ4nHGEVFHx_P3Nu-BlZRFPfzw-_BUL7yjbUARTEQfTTRscCzr4jp5ai7x6dmTN-3&key=AIzaSyDpkuHPvH-X8hZrLrpZbyC2Hi39iAfrLKM","gallery":[]}', '[]', NULL, '{"insider_tip":"C''est un établissement en self-service : on prend son plateau à la cantine et on débarrasse sa table (règle d''or du lieu). Pour le coworking, c''est gratuit de 08:30 à 12:00 et de 14:30 à 17:45 en semaine, avec prises et WiFi. Le soir, l''ambiance devient plus festive avec des bières bio et des cocktails signature comme le Breguet Mule.","specials":{"cuisine":["Bio","Français","Végétarien","Vegan"],"drinks":["Vins nature bio","Bière bio pression (7€)","Breguet Mule","Café artisanal bio"],"must_eat":"La formule midi à 10€ (entrée/plat ou plat/dessert 100% bio) est l''un des meilleurs rapports qualité/prix du quartier. Le ''Bol bio végé'' et le ''Succulent au chocolat'' sont les classiques de la maison. Pour l''afterwork, les tapas bio accompagnées d''un vin nature français.","expert_catchline":"Tiers-lieu 100% bio : cantine saine le midi, coworking studieux et bar festif le soir avec vins nature."}}', 'Le Grand Bréguet est une ''cantine vivante'' nichée au cœur du 11e, à deux pas de la Place de la Bastille. Véritable tiers-lieu 100% bio, l''espace alterne entre café studieux le matin (coworking gratuit), cantine saine le midi (formules dès 10€) et bar à tapas/vins nature le soir. On y trouve de grandes tables en bois, une terrasse spacieuse, un piano et même un baby-foot. L''engagement est total : 90% des produits sont issus de l''agriculture française et l''intégralité de la carte est biologique, y compris les spiritueux.', 'C''est un établissement en self-service : on prend son plateau à la cantine et on débarrasse sa table (règle d''or du lieu). Pour le coworking, c''est gratuit de 08:30 à 12:00 et de 14:30 à 17:45 en semaine, avec prises et WiFi. Le soir, l''ambiance devient plus festive avec des bières bio et des cocktails signature comme le Breguet Mule.', 'Bréguet-Sabin', '["5"]', '[]', 'ChIJX2Ot2vht5kcRlPPv7W_48LA', NULL);
INSERT INTO places_fts VALUES ('poi-le-grand-breguet', 'Le Grand Bréguet', 'restaurant', 'cantine-bio café bar coworking brunch', '17 Rue Bréguet', '', 'Le Grand Bréguet est une ''cantine vivante'' nichée au cœur du 11e, à deux pas de la Place de la Bastille. Véritable tiers-lieu 100% bio, l''espace alterne entre café studieux le matin (coworking gratuit), cantine saine le midi (formules dès 10€) et bar à tapas/vins nature le soir. On y trouve de grandes tables en bois, une terrasse spacieuse, un piano et même un baby-foot. L''engagement est total : 90% des produits sont issus de l''agriculture française et l''intégralité de la carte est biologique, y compris les spiritueux.');
INSERT INTO places VALUES ('poi-passerini', 'Passerini', 'passerini', 'restaurant', 'italian, gastronomic, pasta-specialist, institution', 'culturel', 48.8504043, 2.3739797, 11, '65 Rue de Charenton', '#c499ff', 'pin', 1, 4.5, 0, 'https://maps.googleapis.com/maps/api/place/photo?maxwidth=1600&photo_reference=ATCDNfWFpIDM5V9_74eM-SJiP_8eivedBJBGZ4-Lco24aiNHVDFRrGlQVKocOEHT34o5OUQMcgJ2KI2P7BBFukGHqkeDKlNwSAlIZFbyghaSZ67MShuRH1b8P1372_geYGYyXTVa2kbkoEFLg7tIhwhi-_No_tFcOJKSINWkECAypAVWadWeqQOS6f-N0s3mgzbEMLJTnT1gEE12VHSDsTiCuNfc3oV_ju7P90jBQKCyj6pBrrKQaJ5i-czbG-oAtmW2N-UxrWyE19_Y&key=AIzaSyDpkuHPvH-X8hZrLrpZbyC2Hi39iAfrLKM', NULL, 30, 0, '€', NULL, NULL, 12, 4, 30, 50, '{"chill":50,"festif":40,"culturel":60}', '{}', '["restaurant","italian","gastronomic","pasta-specialist","institution"]', '{"standard":"Mer-Ven: 12:00–14:15, 19:30–22:15; Mar & Sam: 19:30–22:15; Fermé Lun-Dim","display":"Mer-Ven: 12:00–14:15, 19:30–22:15; Mar & Sam: 19:30–22:15; Fermé Lun-Dim","detailed":"Mer-Ven: 12:00–14:15, 19:30–22:15; Mar & Sam: 19:30–22:15; Fermé Lun-Dim"}', '{"opening_hours_raw":"Mer-Ven: 12:00–14:15, 19:30–22:15; Mar & Sam: 19:30–22:15; Fermé Lun-Dim","reservation_policy":"resa_conseillee","terrace":false,"accessibility":true,"wifi":false,"main_action":{"type":"site","url":"http://www.passerini.paris","label":"RÉSERVER"},"happy_hour":null}', '{"avg_budget":65,"is_free":false,"pint_price":0,"wine_glass":12,"coffee_price":4,"dish_price":30,"menu_type":"standard","force_manual_dish_price":true,"last_updated":"2026-03-08","menu_items":[{"category":"Formules Déjeuner (Semaine)","items":[{"name":"Entrée + Pasta","price":"34.00€"},{"name":"Entrée + Pasta + Dessert","price":"42.00€"},{"name":"Entrée + Main Course","price":"37.00€"},{"name":"Entrée + Main Course + Dessert","price":"45.00€"},{"name":"Menu Complet (E+P+M+D)","price":"52.00€"}]},{"category":"Antipasti (Entrées)","items":[{"name":"Trippa alla Romana","price":"22.00€","description":"Tripes à la romaine, menthe et pecorino."},{"name":"Carpaccio de poisson de ligne","price":"24.00€"},{"name":"Artichauts frits & crème de parmesan","price":"20.00€"}]},{"category":"Primi (Pâtes Maison)","items":[{"name":"Tagliatelle au ragoût de canard","price":"28.00€"},{"name":"Ravioli del giorno","price":"31.00€","description":"Fait main chaque matin."},{"name":"Gnudi ricotta & épinards, beurre de sauge","price":"27.00€"}]},{"category":"Secondi (Plats)","items":[{"name":"Pigeon entier rôti & abats","price":"38.00€"},{"name":"Poisson de roche grillé, sauce aux herbes","price":"34.00€"},{"name":"Epaule d''agneau de lait (à partager)","price":"80.00€"}]},{"category":"Dolci","items":[{"name":"Tiramisu Passerini","price":"12.00€"},{"name":"Gelato artisanal minute","price":"10.00€"}]}]}', '{"hero":"https://maps.googleapis.com/maps/api/place/photo?maxwidth=1600&photo_reference=ATCDNfWFpIDM5V9_74eM-SJiP_8eivedBJBGZ4-Lco24aiNHVDFRrGlQVKocOEHT34o5OUQMcgJ2KI2P7BBFukGHqkeDKlNwSAlIZFbyghaSZ67MShuRH1b8P1372_geYGYyXTVa2kbkoEFLg7tIhwhi-_No_tFcOJKSINWkECAypAVWadWeqQOS6f-N0s3mgzbEMLJTnT1gEE12VHSDsTiCuNfc3oV_ju7P90jBQKCyj6pBrrKQaJ5i-czbG-oAtmW2N-UxrWyE19_Y&key=AIzaSyDpkuHPvH-X8hZrLrpZbyC2Hi39iAfrLKM","gallery":[]}', '[]', NULL, '{"insider_tip":"Si les réservations au restaurant sont complètes, essayez ''Passerini & Figli'' juste à côté : c''est sa boutique de pâtes fraîches où l''on peut aussi manger sur le pouce (même si le restaurant reste l''expérience ultime).","specials":{"cuisine":["Gastronomie italienne","Pâtes faites main","Cuisine de marché"],"drinks":["Sélection pointue de vins italiens","Grappa de collection"],"must_eat":"Les raviolis du jour, une démonstration technique et gustative.","must_drink":"Un Barolo ou un vin nature de Sicile."},"expert_catchline":"Le temple de la pasta et l''élégance italienne par le maestro Giovanni Passerini."}', 'Giovanni Passerini est le maître incontesté de la cuisine italienne à Paris. Dans son restaurant épuré et lumineux du 11ème, il sublime le produit brut avec une technique de haute volée. Ses pâtes fraîches, réalisées avec précision, sont devenues une référence absolue pour les amateurs. Pas de folklore ici, juste l''Italie dans ce qu''elle a de plus élégant, moderne et sincère.', 'Si les réservations au restaurant sont complètes, essayez ''Passerini & Figli'' juste à côté : c''est sa boutique de pâtes fraîches où l''on peut aussi manger sur le pouce (même si le restaurant reste l''expérience ultime).', 'Ledru-Rollin', '[8]', '[]', 'ChIJ_U67bYtt5kcRdYt9_U67bYt', NULL);
INSERT INTO places_fts VALUES ('poi-passerini', 'Passerini', 'restaurant', 'italian gastronomic pasta-specialist institution', '65 Rue de Charenton', '', 'Giovanni Passerini est le maître incontesté de la cuisine italienne à Paris. Dans son restaurant épuré et lumineux du 11ème, il sublime le produit brut avec une technique de haute volée. Ses pâtes fraîches, réalisées avec précision, sont devenues une référence absolue pour les amateurs. Pas de folklore ici, juste l''Italie dans ce qu''elle a de plus élégant, moderne et sincère.');
