INSERT INTO places_fts VALUES ('poi-jones', 'Jones', 'restaurant', 'bistronomie fusion italien restaurant', '43 Rue Godefroy Cavaignac', '', 'Derrière sa devanture bleu nuit, Jones s''impose comme une pépite bistronomique infusée d''influences italiennes. Une salle chaleureuse (pierres grattées, vieux miroirs) accueille des assiettes millimétrées, pensées pour être partagées, où la maîtrise des sauces et des cuissons tutoie l''excellence.');
