name":"Burrata fumée, noisettes","price":"14.00€"}]},{"category":"Plats Traditionnels (Weekly)","items":[{"name":"Cassoulet au confit de canard","price":"19.00€","description":"Généreux, haricots de Tarbes."},{"name":"Volaille farcie aux herbes","price":"18.50€"},{"name":"Pêche du jour, beurre blanc","price":"17.00€"}]},{"category":"Douceurs","items":[{"name":"Fromage affiné (Alexis)","price":"8.50€"},{"name":"Mousse au chocolat & sel fumé","price":"9.00€"},{"name":"Fruit de saison rôti, sablé","price":"8.50€"}]},{"category":"Cave & Vermouths","items":[{"name":"Verre de Vin Nature","price":"9.00€","description":"Sélection tournante de pépites."},{"name":"Vermouth artisanal","price":"8.50€"},{"name":"Cocktail Signature","price":"13.00€"}]}]}', '{"hero":"https://maps.googleapis.com/maps/api/place/photo?maxwidth=1600&photo_reference=ATCDNfVtk8sP7AR7_RPMoMeus-D9li2r-ZOU5zAY3x2TFfVxMrBiHipRnQysOT4zsyyFVuboqal8s14Ycz_gI3X-plMVdhY2vv-qiu2vAmoKL4NGLcIRwJvFyOgGml9ghO1UGmUHD7l3LR42c6pHKQNNBNut-Sb1issEtei8Q5Ystg9vz5c6AtGSbIhIP-9tyghXukg2pe4CW3CMKW-Hxz7l01RF7uZpMBrpKiO7obYDEB-CFD_gABJzA7_TeWz5KeCsbw78w3p6QO5fYn4NBKdYQ3Ca2cjA-c23fOs2BSutinSSTg&key=AIzaSyDpkuHPvH-X8hZrLrpZbyC2Hi39iAfrLKM","gallery":[]}', '[]', NULL, '{"insider_tip":"Alexis est un sommelier passionné ; demandez-lui sa sélection de vermouths ou de vins naturels hors-carte, c''est là que réside l''âme du lieu.","specials":{"cuisine":["Charcuterie Maison","Tradition Modernisée","Plats de Grand-Mère"],"drinks":["Natural Wines","Vermouth Specialist","Artisanal Cocktails"],"must_eat":"Le pâté en croûte maison (l''un des meilleurs du quartier).","must_drink":"Un vermouth artisanal sélectionné par Alexis."},"expert_catchline":"Bib Gourmand 2026. L''art de la charcuterie maison et du vin vivant."}', 'Une pépite récompensée par le Bib Gourmand 2026. Lissit (pour l''enfant du pays Alexis Lissitzky) est un lieu à part où la charcuterie maison règne en maître. La cheffe Claire Grumellon y déploie une cuisine de tradition, brute et sincère, qui magnifie le produit sans artifice. Une ambiance de natural wine bar chaleureux où l''on se sent immédiatement chez soi.', 'Alexis est un sommelier passionné ; demandez-lui sa sélection de vermouths ou de vins naturels hors-carte, c''est là que réside l''âme du lieu.', 'Parmentier', '[3]', '[]', 'ChIJs8_Ypldt5kcRG-p8E-Ff2-Q', NULL);
INSERT INTO places_fts VALUES ('poi-lissit', 'Lissit', 'restaurant', 'french bistrot bib-gourmand natural wine', '48 Rue de la Folie Méricourt', '', 'Une pépite récompensée par le Bib Gourmand 2026. Lissit (pour l''enfant du pays Alexis Lissitzky) est un lieu à part où la charcuterie maison règne en maître. La cheffe Claire Grumellon y déploie une cuisine de tradition, brute et sincère, qui magnifie le produit sans artifice. Une ambiance de natural wine bar chaleureux où l''on se sent immédiatement chez soi.');
