6CmiFC_feQeRgG6OrwY8dCVNnR_6TnRM_P9YD0i-sURAGj69erv23GDhUC3izdv79cn2w6bd629aiNl-p03p1EQuOfwvklxTVi7IRG9Dy3m4aq4t3nU0wpK9bKAA5amRKZodRNUKbVAAeT7iEKX_ktOW2rigYWraccmG7ZAY7aFInhLNElEdIu8DpZpKyzCOu6O2h3o4fkzDLnSZHSC09HK0OsB9MsEWXAfbrro-0EK7MiWWWOYFOPtf6uBnBosCHEj2S-Iqq_Jt3XcORC_jPEhiC8Y6KPwFbOlHJK8BWBsYTWgDvGLSVz8zy2ecdnHR-iWXW2D0dYKcNFmxqk7ZjOqRh4BFvamHcnlBb6xoNyiGMYKZ_jCz-Ap2CMdnQWR_rxZl0MjwNdkRLyLn_j8wr4oFn54q5x1_uHcnqCUHq4pPkRYe&key=AIzaSyDpkuHPvH-X8hZrLrpZbyC2Hi39iAfrLKM"]', NULL, '{"insider_tip":"• Pensez à vérifier la programmation en ligne : les concerts (Jazz, Soul, Latin) au sous-sol démarrent souvent vers 20h30/21h00.\n• Prévoyez de manger au RDC avant de descendre boire un verre pour le concert.\n• Les beignets de fleurs de courgettes (13€) et le tartare (15€) font l''unanimité.\n• Ouvert un peu plus tôt que les autres (dès 17h00) pour un afterwork pré-concert.","specials":{"cuisine":["Tartare de Bœuf bergamote","Fleurs de courgettes frites","Ceviche gingembre"],"drinks":["Vins natures purs jus","Cocktails création","Guinness pression"],"must_eat":"Contrairement aux clubs classiques qui négligent la nourriture, ici les assiettes sont de vraies claques (goûtez les keftas en pita).","must_drink":"Laissez le barman improviser un cocktail ''sur mesure'' en fonction du style sonore du soir."},"expert_catchline":"Bistronomie incisive au rez-de-chaussée, jazz club clandestin au sous-sol. Duo gagnant rue de Charonne."}', 'Le bar à manger le plus musical du 11ème. Louloute est un pur hybride : au rez-de-chaussée, on partage d''excellentes assiettes aux influences franco-italiennes (tartares, ceviches, fleurs de courgettes frites) accompagnées de vins natures. L''apothéose se trouve au sous-sol : un authentique club de jazz caché en cave voûtée, avec programmation pointue et jam sessions endiablées.', '• Pensez à vérifier la programmation en ligne : les concerts (Jazz, Soul, Latin) au sous-sol démarrent souvent vers 20h30/21h00.
INSERT INTO places_fts VALUES ('poi-louloute', 'Louloute', 'restaurant', 'bar à manger bistronomique jazz club restaurant club', '55 Rue de Charonne', '', 'Le bar à manger le plus musical du 11ème. Louloute est un pur hybride : au rez-de-chaussée, on partage d''excellentes assiettes aux influences franco-italiennes (tartares, ceviches, fleurs de courgettes frites) accompagnées de vins natures. L''apothéose se trouve au sous-sol : un authentique club de jazz caché en cave voûtée, avec programmation pointue et jam sessions endiablées.');
INSERT INTO places VALUES ('poi-pause-cafe', 'Le Pause Café', 'pause-cafe', 'restaurant', 'Bistro, Café, Méditerranéen, Institution', 'chill', 48.8524, 2.3735, 11, '41 Rue de Charonne, 75011 Paris', '#8ccaf7', 'pin', 1, 4.1, 0, 'https://lh3.googleusercontent.com/p/AF1QipN_XQ_XQ_XQ_XQ_XQ_XQ_XQ_XQ_XQ_XQ_XQ_XQ=s1360-w1360-h1020', NULL, 13.75, NULL, '€', NULL, NULL, NULL, NULL, 13.75, 50, '{"chill":80,"festif":40,"culturel":10}', '{}', '["restaurant","Bistro","Café","Méditerranéen","Institution"]', '{"standard":"Lun-Sam: 08:00–02:00\nDim: 09:00–21:00","display":"Lun-Sam: 08:00–02:00","detailed":"Lun-Sam: 08:00–02:00\nDim: 09:00–21:00"}', '{"reservation_policy":"sans_resa","accessibility":true,"wifi":true,"terrace":true,"vegan_friendly":true,"opening_hours_raw":"Lun-Sam: 08:00–02:00\nDim: 09:00–21:00","main_action":{"type":"site","url":"https://www.instagram.com/le_pause_cafe/","label":"VOIR LE LIEU"},"happy_hour":null}', '{"avg_budget":25,"dish_price":13.75,"last_updated":"2026-03-08","menu_items":[{"category":"Petit-Déjeuner (9:00 - 11:30)","items":[{"name":"Le Petit Déj Classique","price":"11.00€","description":"Hot drink, juice, pastry, tartine."},{"name":"Le Petit Déj Complet","price":"14.00€","description":"Déj Classique + Œuf bio crème de Comté."},{"name":"Œufs Pochés Bio en Cocotte","price":"6.00€","description":"Ciboulette et mouillettes."},{"name":"Granola Bowl Maison","price":"6.50€"},{"name":"Croissant / Pain au Chocolat","price":"2.00€"},{"name":"Tartine Beurre & Confiture","price":"3.00€"}]},{"category":"Bistro & Plats (Midi & Soir)","items":[{"name":"Cheeseburger Pause Café","price":"14.50€","description":"Bœuf français, cheddar 9 mois, frites maison."},{"name":"Fish n Chips Maison","price":"14.00€","description":"Cabillaud pané, sauce tartare, citron vert."},{"name":"Poulet Crousti-Crousti","price":"13.50€","description":"Poulet pané hyper croustillant, purée fine."},{"name":"Le Dhal de Lentilles Corail (V)","price":"13.00€","description":"Curry vert, épinards, riz coco."},{"name":"Saumon Laqué Teriyaki","price":"14.50€","description":"Sriracha, riz coco, herbes."},{"name":"Pulled Pork Sandwich","price":"13.50€","description":"Coleslaw, ginger BBQ, frites maison."},{"name":"Burger Veggie (Halloumi & Portobello)","price":"14.00€","description":"Chou rouge, frites de patate douce."},{"name":"Thon à la Plancha","price":"16.50€"},{"name":"Tartare de Bœuf Tradition","price":"13.50€"},{"name":"Parmentier de Canard","price":"12.50€"},{"name":"Entrecôte Belle de l''Ouest","price":"16.50€"}]},{"category":"Grandes Salades & Snack","items":[{"name":"Salade Louisiane","price":"14.50€","description":"Crousti-poulet, mozza, oignons frits, sauce Caesar."},{"name":"Salade Crispy Caesar","price":"14.00€"},{"name":"Salade de Légumes Croquants & Brique de Chèvre","price":"12.80€"},{"name":"Houmous Maison à la Betterave","price":"7.50€"},{"name":"Falafels de Lentilles Corail","price":"7.00€"},{"name":"Tarama Blanc & Blinis","price":"6.50€"}]},{"category":"Desserts Maison","items":[{"name":"Le Cookie qui Coule","price":"4.50€"},{"name":"Sticky Rice au Lait de Coco & Mangue","price":"6.50€"},{"name":"Gâteau au Chocolat Sans Gluten","price":"6.50€"},{"name":"Cheesecake New York Style","price":"7.00€"},{"name":"Tiramisu Traditionnel","price":"6.00€"}]},{"category":"Boissons & Cafés Spécialités","items":[{"name":"Espresso Pause Blend","price":"2.00€"},{"name":"Dirty Chai Latte","price":"4.50€"},{"name":"Iced Flat White","price":"4.50€"},{"name":"Smoothie Tweety (Exotique)","price":"6.50€"},{"name":"Bissap Maison (Hibiscus)","price":"4.00€"},{"name":"Thé Glacé Maison","price":"4.00€"},{"name":"Bière Demory Paris (Pression)","price":"7.50€"},{"name":"Hugo Spritz","price":"8.50€"},{"name":"Cidre Bio Galipette","price":"6.00€"}]}]}', '{"hero":"https://lh3.googleusercontent.com/p/AF1QipN_XQ_XQ_XQ_XQ_XQ_XQ_XQ_XQ_XQ_XQ_XQ_XQ=s1360-w1360-h1020","gallery":["https://lh3.googleusercontent.com/p/AF1QipN_XQ_XQ_XQ_XQ_XQ_XQ_XQ_XQ_XQ_XQ_XQ_XQ=s1360-w1360-h1020"]}', '["https://lh3.googleusercontent.com/p/AF1QipN_XQ_XQ_XQ_XQ_XQ_XQ_XQ_XQ_XQ_XQ_XQ_XQ=s1360-w1360-h1020"]', NULL, '{"insider_tip":"• La terrasse est chauffée l''hiver, ce qui en fait le spot de repli parfait pour observer le passage rue de Charonne.\n• Le tartare est l''un des plus réguliers du quartier, servi comme il se doit avec des frites maison.\n• C''est l''un des rares endroits du coin à garder un esprit ''brasserie de village'' malgré la hype environnante.\n• Idéal pour un café-journal le matin avant que la foule n''arrive.","specials":{"cuisine":["Bistro Français","Tartare","Burgers"],"drinks":["Pression Blonde Pause","Aperol Spritz","Café Allongé"],"must_eat":"Le tartare au couteau et les frites maison."},"expert_catchline":"L''institution de la rue de Charonne : la terrasse mythique des rendez-vous de Bastille."}', 'Le Pause Café est une véritable institution de Bastille, rendue célèbre par le film ''Chacun cherche son chat''. Avec sa méga-terrasse qui ne désemplit jamais, c''est le point de ralliement du quartier depuis des décennies. À l''intérieur, le cadre rétro avec ses grandes banquettes en cuir invite à la flânerie. On y sert une cuisine de bistro honnête et généreuse, du petit-déjeuner matinal au dernier verre de 2h du mat.', '• La terrasse est chauffée l''hiver, ce qui en fait le spot de repli parfait pour observer le passage rue de Charonne.
INSERT INTO places_fts VALUES ('poi-pause-cafe', 'Le Pause Café', 'restaurant', 'Bistro Café Méditerranéen Institution', '41 Rue de Charonne, 75011 Paris', '', 'Le Pause Café est une véritable institution de Bastille, rendue célèbre par le film ''Chacun cherche son chat''. Avec sa méga-terrasse qui ne désemplit jamais, c''est le point de ralliement du quartier depuis des décennies. À l''intérieur, le cadre rétro avec ses grandes banquettes en cuir invite à la flânerie. On y sert une cuisine de bistro honnête et généreuse, du petit-déjeuner matinal au dernier verre de 2h du mat.');
