ce":"11.00€"},{"name":"Kafta de canard sur houmous","price":"12.00€"},{"name":"Warak enab (feuilles de vigne) à l''agneau","price":"16.00€"},{"name":"Falafels maison & tarator","price":"9.50€"},{"name":"Houmous classique revisité","price":"8.00€"},{"name":"Labné à la menthe séchée","price":"7.50€"}]},{"category":"Brunch Libanais (Weekend)","items":[{"name":"Formule Terwi''a (Menu complet)","price":"34.00€"}]},{"category":"Desserts","items":[{"name":"Awaymettes (beignets sirop orange)","price":"9.00€"},{"name":"Poire pochée à l''arak","price":"9.00€"},{"name":"Flan Libanais à la fleur d''oranger","price":"8.50€"}]}]}', '{"hero":"https://maps.googleapis.com/maps/api/place/photo?maxwidth=1600&photo_reference=ATCDNfWv5D-3u9G-O_vX-H4nK-R-nQ--jM--jM--jM--jM--jM--jM--jM--jM--jM--jM--jM--jM--jM--jM--jM--jM--jM--jM--jM--jM--jM--jM--jM--jM--jM--jM--jM--jM--jM--jM--jM--jM--jM--jM--jM--jM--jM--jM--jM--jM--jM--jM--jM--jM--jM--jM--jM--jM--jM--jM--jM--jM--jM--jM--jM--jM--jM--jM--jM--jM--jM--jM--jM--jM--jM--jM--jM--jM&key=AIzaSyDpkuHPvH-X8hZrLrpZbyC2Hi39iAfrLKM","gallery":[]}', '[]', NULL, '{"insider_tip":"Ne faites pas l''impasse sur le feuilleté Batata, c''est une merveille de textures. Le brunch est souvent complet, réservez bien à l''avance.","specials":{"cuisine":["Libanais Créatif","Bistronomie du Levant","Mezzés revisités"],"drinks":["Vins du Liban et d''ailleurs","Arak sélectionné"],"must_eat":"Le feuilleté Batata et les brochettes Taouk à la pistache.","must_drink":"Un verre de Château Musar pour accompagner la viande."},"expert_catchline":"La cuisine levantine en mode bistronomie : solaire, créative et passionnée."}', 'Sama Bistro est une lettre d''amour à la cuisine libanaise, réinterprétée avec la finesse d''un bistrot contemporain. Ici, les saveurs du Proche-Orient s''émancipent des clichés pour proposer des assiettes solaires, techniques et extrêmement généreuses. Le cadre est lumineux, l''accueil vibrant, et le brunch du weekend est déjà une institution pour les amateurs de Terwi''a authentique.', 'Ne faites pas l''impasse sur le feuilleté Batata, c''est une merveille de textures. Le brunch est souvent complet, réservez bien à l''avance.', 'Rue Saint-Maur', '[3]', '[]', '0x47e66d57cc1a8e4f:0x4d6e22cf47a4d45b', NULL);
INSERT INTO places_fts VALUES ('poi-sama-bistro', 'Sama Bistro', 'restaurant', 'lebanese bistronmic fusion creative', '5 Rue Guillaume Bertrand', '', 'Sama Bistro est une lettre d''amour à la cuisine libanaise, réinterprétée avec la finesse d''un bistrot contemporain. Ici, les saveurs du Proche-Orient s''émancipent des clichés pour proposer des assiettes solaires, techniques et extrêmement généreuses. Le cadre est lumineux, l''accueil vibrant, et le brunch du weekend est déjà une institution pour les amateurs de Terwi''a authentique.');
INSERT INTO places VALUES ('poi-street-bangkok-bastille', 'Street Bangkok (Bastille)', 'street-bangkok-bastille', 'restaurant', 'Thaïlandais, Street Food, BBQ Thaï, Populaire', 'chill', 48.8545, 2.3705, 11, '13 Rue de la Roquette, 75011 Paris', '#8ccaf7', 'pin', 1, 4.4, 0, 'https://streetbangkok.fr/wp-content/uploads/2021/04/Street-Bangkok-Bastille-Design.jpg', NULL, 17.5, NULL, '€', NULL, NULL, NULL, NULL, 17.5, 50, '{"chill":50,"festif":50,"culturel":10}', '{}', '["restaurant","Thaïlandais","Street Food","BBQ Thaï","Populaire"]', '{"standard":"Lundi-Dimanche: 12:00–01:00","display":"Lundi-Dimanche: 12:00–01:00","detailed":"Lundi-Dimanche: 12:00–01:00"}', '{"reservation_policy":"sans_resa","accessibility":true,"wifi":false,"terrace":true,"vegan_friendly":true,"opening_hours_raw":"Lundi-Dimanche: 12:00–01:00","main_action":{"type":"site","url":"https://streetbangkok.fr/","label":"COMMANDER"},"happy_hour":null}', '{"avg_budget":18,"dish_price":17.5,"last_updated":"2026-03-08","index_price":13,"menu_items":[{"category":"Grillades & BBQ Thaï (Flamme & Braise)","items":[{"name":"Sate Gai (x3) - Entrée","price":"11.00€","description":"Brochettes de poulet coco-curry-curcuma."},{"name":"BBQ Ribs Secret Sauce","price":"18.50€","description":"Travers de porc laqués, sauce ail secrète."},{"name":"Tigre Qui Pleure","price":"19.50€","description":"Bœuf mariné citronnelle & huile d''échalote."},{"name":"Gai Yang (Cuisse de Poulet)","price":"17.00€","description":"Désossée, laquée et grillée à la flamme."},{"name":"Sate Gai (Plat)","price":"15.50€"},{"name":"Mix 2 Viandes (Poulet & Porc)","price":"28.00€"},{"name":"Crying Beef Salad","price":"18.00€"}]},{"category":"Le Wok (Saisis à Haute Température)","items":[{"name":"Pad Thaï Crevettes","price":"16.50€","description":"Noodles de riz, tamarin, cacahuètes, crevettes."},{"name":"Pad Thaï Poulet","price":"15.50€"},{"name":"Pad Ka Prao Poulet Gai Yang","price":"17.50€","description":"Basilic sacré, piment, ail, œuf frit."},{"name":"Pad Ka Prao Tofu (V)","price":"15.00€"},{"name":"Pad See Ew Bœuf","price":"16.50€","description":"Larges nouilles de riz, brocoli chinois."},{"name":"Fried Rice Crab","price":"19.00€"}]},{"category":"Curries Onctueux (Lait de Coco & Épices)","items":[{"name":"Red Curry Gai Yang","price":"18.50€","description":"Lait de coco, feuilles de kaffir, poulet grillé."},{"name":"Panang Curry Crevettes","price":"19.00€"},{"name":"Green Curry Tofu & Aubergines","price":"16.00€"},{"name":"Massaman Beef","price":"18.50€","description":"Mijoté, pommes de terre, cacahuètes."}]},{"category":"Som Tam & Sides","items":[{"name":"Som Tam (Salade Papaye Verte)","price":"9.50€","description":"Piment, citron vert, cacahuètes."},{"name":"Tom Kha Kai (Soupe Coco)","price":"6.50€"},{"name":"Salade de Concombre Sésame","price":"5.50€"},{"name":"Hot Pickles Maison","price":"4.50€"},{"name":"Jasmin Rice","price":"3.50€"},{"name":"Sticky Rice","price":"4.00€"},{"name":"Légumes Sautés au Wok","price":"7.00€"}]},{"category":"Cocktails & Softs Signature","items":[{"name":"Khao Mule (Cocktail)","price":"12.00€","description":"Vodka, gingembre, piment, citronnelle."},{"name":"Bangkok Garden","price":"13.00€","description":"Gin, basilic thaï, concombre."},{"name":"Limonade Gingembre Maison","price":"5.50€"},{"name":"Bière Singha (33cl)","price":"6.50€"},{"name":"Thé Glacé Thaï (Lait de coco)","price":"6.00€"},{"name":"Jus de Coco Frais","price":"6.50€"}]},{"category":"Desserts","items":[{"name":"Mango Sticky Rice","price":"9.00€"},{"name":"Banane Frite au Miel","price":"7.50€"},{"name":"Mochi Glacé (x2)","price":"6.00€"}]}]}', '{"hero":"https://streetbangkok.fr/wp-content/uploads/2021/04/Street-Bangkok-Bastille-Design.jpg","gallery":["https://lh3.googleusercontent.com/p/AF1QipN_XQ_XQ_XQ_XQ_XQ_XQ_XQ_XQ_XQ_XQ_XQ_XQ=s1360-w1360-h1020"]}', '["https://lh3.googleusercontent.com/p/AF1QipN_XQ_XQ_XQ_XQ_XQ_XQ_XQ_XQ_XQ_XQ_XQ_XQ=s1360-w1360-h1020"]', NULL, '{"insider_tip":"• Le Tigre qui pleure est la star absolue du lieu, demandez-le bien piquant si vous osez.\n• Ouvert jusqu''à 1h du matin, c''est le spot parfait pour un manger un vrai plat après quelques verres.\n• Le Pad Ka Prao est l''un des plus authentiques de Paris (attention au piment).\n• Goûtez leur thé glacé citronnelle maison pour éteindre le feu du curry.","specials":{"cuisine":["Thaïlandais","Street BBQ","Pad Thaï"],"drinks":["Bière Singha","Nam Manao","Thé Citronnelle"],"must_eat":"Le Tigre qui pleure et la salade de papaye verte."},"expert_catchline":"Le meilleur du BBQ thaï au charbon de bois et des currys explosifs à Bastille."}', 'Le temple de la street food thaïlandaise à Bastille. On y vient pour les grillades au charbon de bois (Meat BBQ) qui embaument la rue de la Roquette, et pour l''énergie débordante du lieu. Inspiré par les marchés de nuits de Bangkok, le décor est brut, néonisé et sonore. C''est pimenté, c''est bruyant, c''est bon.', '• Le Tigre qui pleure est la star absolue du lieu, demandez-le bien piquant si vous osez.
INSERT INTO places_fts VALUES ('poi-street-bangkok-bastille', 'Street Bangkok (Bastille)', 'restaurant', 'Thaïlandais Street Food BBQ Thaï Populaire', '13 Rue de la Roquette, 75011 Paris', '', 'Le temple de la street food thaïlandaise à Bastille. On y vient pour les grillades au charbon de bois (Meat BBQ) qui embaument la rue de la Roquette, et pour l''énergie débordante du lieu. Inspiré par les marchés de nuits de Bangkok, le décor est brut, néonisé et sonore. C''est pimenté, c''est bruyant, c''est bon.');
INSERT INTO places VALUES ('poi-superfine', 'Superfine', 'superfine', 'restaurant', 'dive-bar, street-food, cocktails, vibrant, restaurant', 'festif', 48.854235, 2.376892, 11, '86 Rue de la Roquette', '#ffab60', 'pin', 1, 4.8, 0, 'https://maps.googleapis.com/maps/api/place/photo?maxwidth=1600&photo_reference=ATCDNfX_J-mU_W05_V5--jM--jM--jM--jM--jM--jM--jM--jM--jM--jM--jM--jM--jM--jM--jM--jM--jM--jM--jM--jM--jM--jM--jM--jM--jM--jM--jM--jM--jM--jM--jM--jM--jM--jM--jM--jM--jM--jM--jM--jM--jM--jM--jM--jM--jM--jM--jM--jM--jM--jM--jM--jM--jM--jM--jM--jM--jM--jM--jM--jM--jM--jM--jM--jM--jM--jM--jM--jM&key=AIzaSyDpkuHPvH-X8hZrLrpZbyC2Hi39iAfrLKM', NULL, 13, 0, '€', 8, NULL, 7, 0, 13, 50, '{"chill":20,"festif":90,"culturel":10}', '{}', '["restaurant","dive-bar","street-food","cocktails","vibrant","restaurant"]', '{"standard":"Mar-Sam: 18:00–02:00; Dim: 17:00–00:00; Fermé Lundi","display":"Mar-Sam: 18:00–02:00; Dim: 17:00–00:00; Fermé Lundi","detailed":"Mar-Sam: 18:00–02:00; Dim: 17:00–00:00; Fermé Lundi"}', '{"opening_hours_raw":"Mar-Sam: 18:00–02:00; Dim: 17:00–00:00; Fermé Lundi","reservation_policy":"sans_resa","terrace":true,"accessibility":true,"wifi":false,"main_action":{"type":"site","url":"https://www.instagram.com/superfine.paris/","label":"INSTAGRAM"},"happy_hour":null}', '{"avg_budget":35,"is_free":false,"pint_price":8,"wine_glass":7,"coffee_price":0,"dish_price":13,"last_updated":"2026-03-09","menu_items":[{"category":"Sexy Street Food (Les Incontournables)","items":[{"name":"Superdog","price":"13.00€","description":"Saucisse volaille, oignons Guinness, relish curcuma, cheddar gratiné."},{"name":"Eggplant Katsu Burger","price":"12.00€","description":"Ketchup miso, chou blanc fermenté, brioche toastée."},{"name":"Puff Pizza Ricotta & Harissa","price":"13.00€","description":"Pâte aérienne, sauce beurre-harissa, miel."},{"name":"Puff Pizza Pepperoni","price":"15.00€","description":"Crème de ricotta, provolone, pepperoni piquant."},{"name":"Pasta al Ragù Bianco","price":"14.50€","description":"Pâtes fraîches, ragù blanc, espuma parmesan."},{"name":"Crispy Po''Boy","price":"14.00€","description":"Crevettes frites, sauce cajun, pickles maison."},{"name":"Fried Chicken & Hot Honey","price":"12.50€"},{"name":"Cheeseburger Superfine","price":"13.00€"}]},{"category":"Bites & Sides (À partager)","items":[{"name":"Shiitake Mushroom Skewers","price":"9.00€","description":"Brochettes de shiitake laquées soja-gingembre."},{"name":"Reimagined Caesar Salad","price":"9.00€"},{"name":"Dirty Fries Superfine","price":"7.00€"},{"name":"Pickles de légumes de saison","price":"5.00€"},{"name":"Croquettes de Cochon & Mayo fumée","price":"8.50€"},{"name":"Burrata, Huile de Basilic & Noisettes","price":"11.00€"},{"name":"Maïs Grillé, Beurre de Miso & Furikake","price":"7.50€"}]},{"category":"Cocktails Signature (L''Alchimie)","items":[{"name":"Absinthe Gimlet","price":"14.00€","description":"Absinthe, amaretto blanc, citron, sauge."},{"name":"Not A Bloody Mary","price":"14.00€","description":"Mezcal, dashi, ananas, céleri, harissa."},{"name":"White Forest Martini","price":"14.00€","description":"Gin, vodka, sake, liqueur de sapin, estragon."},{"name":"PB&B Milkshake (Boozy)","price":"13.50€","description":"Bourbon, peanut butter, banane, vanille, chantilly fumée."},{"name":"Butter Not Texture","price":"14.00€","description":"Gin, shochu d''orge, sarrasin, butternut."},{"name":"Fortunella Spritz","price":"12.00€"},{"name":"New College (Cognac & Olive)","price":"14.00€"},{"name":"Super-Negroni (Barrel aged)","price":"13.00€"},{"name":"Mezcal Mule","price":"12.00€"},{"name":"Espresso Martini Superfine","price":"12.00€"}]},{"category":"Softs & Mocktails","items":[{"name":"Mocktail Curry & Amande","price":"10.00€"},{"name":"Mocktail Cardamome & Café","price":"10.00€"},{"name":"Limonade artisanale (citron-gingembre)","price":"6.00€"},{"name":"Thé Glacé Maison (pêche-verveine)","price":"6.00€"},{"name":"Cola Baladin (Artisanal)","price":"5.50€"}]},{"category":"Beers & Natural Wines","items":[{"name":"Pression : Guinness (33cl)","price":"8.00€"},{"name":"Pression : NEIPA Cloudy Job (33cl)","price":"8.00€"},{"name":"Can : Fauve Craft Beer (33cl)","price":"9.00€"},{"name":"Vin Naturel Rouge (Verre)","price":"8.50€"},{"name":"Vin Naturel Orange (Verre)","price":"9.50€"},{"name":"Bouteille Vin Naturel (à partir de)","price":"38.00€"}]}]}', '{"hero":"https://maps.googleapis.com/maps/api/place/photo?maxwidth=1600&photo_reference=ATCDNfX_J-mU_W05_V5--jM--jM--jM--jM--jM--jM--jM--jM--jM--jM--jM--jM--jM--jM--jM--jM--jM--jM--jM--jM--jM--jM--jM--jM--jM--jM--jM--jM--jM--jM--jM--jM--jM--jM--jM--jM--jM--jM--jM--jM--jM--jM--jM--jM--jM--jM--jM--jM--jM--jM--jM--jM--jM--jM--jM--jM--jM--jM--jM--jM--jM--jM--jM--jM--jM--jM--jM--jM&key=AIzaSyDpkuHPvH-X8hZrLrpZbyC2Hi39iAfrLKM","gallery":[]}', '[]', NULL, '{"insider_tip":"• Ne passez pas à côté de la ''Puff Pizza'' à la harissa et au miel, une tuerie absolue.\n• Le cocktail ''Not A Bloody Mary'' est une masterclass de limpidité et de piquant.\n• Happy hour sur les pressions craft en début de soirée.\n• Les places au bar sont les meilleures pour observer les mixologues à l''œuvre.","specials":{"cuisine":["Puff Pizza Ricotta & Harissa","Superdog Guinness","Eggplant Katsu Burger"],"drinks":["Absinthe Gimlet","Natural Wine Selection","Guinness on tap"],"must_eat":"La Puff Pizza Pepperoni, incroyable de légèreté, suivie d''un Superdog bien gratiné.","must_drink":"L''Absinthe Gimlet pour son équilibre parfait entre fraîcheur et herbalité."},"expert_catchline":"Le dive bar 2.0 de la Roquette : street food sexy et cocktails d''avant-garde dans une ambiance survoltée."}', 'Nouveau bastion de la nuit roquette, Superfine a investi l''ancien Motel pour créer un ''dive bar'' ultra-léché. Ici, le street food se veut ''sexy'' (pizze soufflées, superdogs) et les cocktails s''aventurent dans des territoires audacieux (dashi, absinthe, sapin). DJ sets, acoustique soignée et ambiance électrique : l''adresse est déjà le nouveau QG de l''Est parisien branché.', '• Ne passez pas à côté de la ''Puff Pizza'' à la harissa et au miel, une tuerie absolue.
INSERT INTO places_fts VALUES ('poi-superfine', 'Superfine', 'restaurant', 'dive-bar street-food cocktails vibrant restaurant', '86 Rue de la Roquette', '', 'Nouveau bastion de la nuit roquette, Superfine a investi l''ancien Motel pour créer un ''dive bar'' ultra-léché. Ici, le street food se veut ''sexy'' (pizze soufflées, superdogs) et les cocktails s''aventurent dans des territoires audacieux (dashi, absinthe, sapin). DJ sets, acoustique soignée et ambiance électrique : l''adresse est déjà le nouveau QG de l''Est parisien branché.');
INSERT INTO places VALUES ('poi-le-tagine', 'Le Tagine', 'le-tagine', 'restaurant', 'moroccan, traditional, institution, couscous-specialist', 'chill', 48.863119, 2.366224, 11, '13 Rue Crussol', '#8ccaf7', 'pin', 1, 4.5, 0, 'https://maps.googleapis.com/maps/api/place/photo?maxwidth=1600&photo_reference=ATCDNfWv5D-3u9G-O_vX-H4nK-R-nQ--jM--jM--jM--jM--jM--jM--jM--jM--jM--jM--jM--jM--jM--jM--jM--jM--jM--jM--jM--jM--jM--jM--jM--jM--jM--jM--jM--jM--jM--jM--jM--jM--jM--jM--jM--jM--jM--jM--jM--jM--jM--jM--jM--jM--jM--jM--jM--jM--jM--jM--jM--jM--jM--jM--jM--jM--jM--jM--jM--jM--jM--jM--jM--jM--jM--jM--jM--jM&key=AIzaSyDpkuHPvH-X8hZrLrpZbyC2Hi39iAfrLKM', NULL, 26, 0, '€', NULL, NULL, 8, 3, 26, 50, '{"chill":70,"festif":40,"culturel":60}', '{}', '["restaurant","moroccan","traditional","institution","couscous-specialist"]', '{"standard":"Mer-Dim: 12:00–13:30, 19:00–22:30; Mar: 19:00–22:30; Fermé Lun","display":"Mer-Dim: 12:00–13:30, 19:00–22:30; Mar: 19:00–22:30; Fermé Lun","detailed":"Mer-Dim: 12:00–13:30, 19:00–22:30; Mar: 19:00–22:30; Fermé Lun"}', '{"opening_hours_raw":"Mer-Dim: 12:00–13:30, 19:00–22:30; Mar: 19:00–22:30; Fermé Lun","reservation_policy":"resa_conseillee","terrace":false,"accessibility":true,"wifi":false,"main_action":{"type":"site","url":"http://www.letagine-restaurant.com","label":"RÉSERVER"},"happy_hour":null}', '{"avg_budget":42,"is_free":false,"pint_price":0,"wine_glass":8,"coffee_price":3,"dish_price":26,"menu_type":"standard","force_manual_dish_price":true,"last_updated":"2026-03-08","menu_items":[{"category":"Entrées Traditionnelles","items":[{"name":"Pastilla au Pigeonneau","price":"26.00€","description":"Le grand classique sucré-salé, d''une finesse rare."},{"name":"Méchouïa (Salade de tomates et poivrons grillés)","price":"15.00€"},{"name":"Merguez grillées & salade marocaine","price":"15.00€"},{"name":"Brick à l''œuf de poule de Marans","price":"12.00€"}]},{"category":"Les Tagines (Cuisinés en poterie)","items":[{"name":"Tagine d''Agneau aux olives et citrons confits","price":"27.00€"},{"name":"Tagine de Poulet fermier aux poires & miel","price":"25.00€"},{"name":"Tagine de Saumon aux légumes frais","price":"34.00€"},{"name":"Tagine d''Agneau aux raisins secs & amandes","price":"27.00€"}]},{"category":"Les Couscous (Graines roulées main)","items":[{"name":"Couscous Méchoui (Gigot d''agneau de lait)","price":"34.00€"},{"name":"Couscous Royal (3 viandes : Poulet, Agneau, Merguez)","price":"34.00€"},{"name":"Couscous Merguez (x3)","price":"24.00€"},{"name":"Couscous Légumes frais","price":"22.00€"}]},{"category":"Desserts & Thé","items":[{"name":"Pâtisseries marocaines maison (l''assiette)","price":"12.00€"},{"name":"Salade d''oranges à la cannelle","price":"9.00€"},{"name":"Thé à la menthe traditionnel (verre)","price":"4.50€"}]}]}', '{"hero":"https://maps.googleapis.com/maps/api/place/photo?maxwidth=1600&photo_reference=ATCDNfWv5D-3u9G-O_vX-H4nK-R-nQ--jM--jM--jM--jM--jM--jM--jM--jM--jM--jM--jM--jM--jM--jM--jM--jM--jM--jM--jM--jM--jM--jM--jM--jM--jM--jM--jM--jM--jM--jM--jM--jM--jM--jM--jM--jM--jM--jM--jM--jM--jM--jM--jM--jM--jM--jM--jM--jM--jM--jM--jM--jM--jM--jM--jM--jM--jM--jM--jM--jM--jM--jM--jM--jM--jM--jM--jM--jM&key=AIzaSyDpkuHPvH-X8hZrLrpZbyC2Hi39iAfrLKM","gallery":[]}', '[]', NULL, '{"insider_tip":"Demandez leur pastilla au pigeonneau en entrée, c''est sans doute l''une des meilleures de la capitale. Et n''oubliez pas de goûter aux vins du Maroc, souvent méconnus mais excellents avec leurs plats épicés.","specials":{"cuisine":["Gastronomie marocaine","Couscous traditionnel","Cuisine en terre cuite"],"drinks":["Grands vins du Maroc","Thé à la menthe frais"],"must_eat":"Le Couscous Méchoui (agneau de lait) et la Pastilla au Pigeonneau.","must_drink":"Un Guerrouane ou un vin de l''Atlas."},"expert_catchline":"L''excellence de la cuisine marocaine traditionnelle : couscous d''orfèvre et tagines fondants."}', 'Le Tagine est bien plus qu''un restaurant, c''est une institution marocaine à Paris depuis plus de 30 ans. Ici, la gastronomie du Maghreb est traitée avec un respect immense : les graines de couscous sont roulées à la main, les épices sont sourcées avec soin et les cuissons en tagine de terre cuite sont d''une tendreté absolue. Le décor, parsemé de zelliges et de lanternes, invite au voyage dans une atmosphère élégante et chaleureuse.', 'Demandez leur pastilla au pigeonneau en entrée, c''est sans doute l''une des meilleures de la capitale. Et n''oubliez pas de goûter aux vins du Maroc, souvent méconnus mais excellents avec leurs plats épicés.', 'Oberkampf', '[5,9]', '[]', 'ChIJW0-v__tt5kcRrW0-v__tt5k', NULL);
INSERT INTO places_fts VALUES ('poi-le-tagine', 'Le Tagine', 'restaurant', 'moroccan traditional institution couscous-specialist', '13 Rue Crussol', '', 'Le Tagine est bien plus qu''un restaurant, c''est une institution marocaine à Paris depuis plus de 30 ans. Ici, la gastronomie du Maghreb est traitée avec un respect immense : les graines de couscous sont roulées à la main, les épices sont sourcées avec soin et les cuissons en tagine de terre cuite sont d''une tendreté absolue. Le décor, parsemé de zelliges et de lanternes, invite au voyage dans une atmosphère élégante et chaleureuse.');
INSERT INTO places VALUES ('poi-tarantula', 'Tarántula', 'tarantula', 'restaurant', 'mexican, cantina, modern, natural-wine', 'festif', 48.8553057, 2.375595, 11, '13 bis Rue Keller', '#ffab60', 'pin', 1, 4.8, 0, 'https://maps.googleapis.com/maps/api/place/photo?maxwidth=1600&photo_reference=ATCDNfWv5D-3u9G-O_vX-H4nK-R-nQ--jM--jM--jM--jM--jM--jM--jM--jM--jM--jM--jM--jM--jM--jM--jM--jM--jM--jM--jM--jM--jM--jM--jM--jM--jM--jM--jM--jM--jM--jM--jM--jM--jM--jM--jM--jM--jM--jM--jM--jM--jM--jM--jM--jM--jM--jM--jM--jM--jM--jM--jM--jM--jM--jM--jM--jM--jM--jM--jM--jM--jM--jM--jM--jM--jM--jM--jM--jM&key=AIzaSyDpkuHPvH-X8hZrLrpZbyC2Hi39iAfrLKM', NULL, 24, 0, '€', NULL, NULL, 7, 3.5, 24, 50, '{"chill":60,"festif":70,"culturel":40}', '{}', '["restaurant","mexican","cantina","modern","natural-wine"]', '{"standard":"Mar-Sam: 18:00–00:00 (01:30 Sam); Fermé Lun-Dim","display":"Mar-Sam: 18:00–00:00 (01:30 Sam); Fermé Lun-Dim","detailed":"Mar-Sam: 18:00–00:00 (01:30 Sam); Fermé Lun-Dim"}', '{"opening_hours_raw":"Mar-Sam: 18:00–00:00 (01:30 Sam); Fermé Lun-Dim","reservation_policy":"resa_conseillee","terrace":false,"accessibility":true,"wifi":false,"main_action":{"type":"site","url":"https://www.instagram.com/tarantulaparis/","label":"INSTAGRAM"},"happy_hour":null}', '{"avg_budget":55,"is_free":false,"pint_price":0,"wine_glass":7,"coffee_price":3.5,"dish_price":24,"menu_type":"standard","force_manual_dish_price":true,"last_updated":"2026-03-08","menu_items":[{"category":"Antojitos (Petites Assiettes)","items":[{"name":"Tacos de champignons sauvages ''hallucinogènes''","price":"12.00€"},{"name":"Oignon Roscoff rôti au piment jaune","price":"14.00€"},{"name":"Tuna Crudo, sauce chilaca","price":"18.00€"},{"name":"Empanada croustillante de Chicharrón","price":"11.00€"}]},{"category":"Platos Fuertes (Plats à partager)","items":[{"name":"Demi-poulet rôti au beurre de piment japone","price":"28.00€"},{"name":"Entrecôte (500g) sauce Café de Paris Mexicana","price":"52.00€","description":"Idéal pour deux."},{"name":"Tacos Cantinero (boeuf braisé lentement)","price":"24.00€"},{"name":"Lieu jaune, salsa verde & herbes fraîches","price":"26.00€"}]},{"category":"Postres (Desserts)","items":[{"name":"Flan au caramel, huile d''olive & romarin frit","price":"10.00€","description":"Le dessert signature incontournable."},{"name":"Gâteau de maïs, crème de Mezcal","price":"9.50€"}]},{"category":"Bebidas","items":[{"name":"Margarita Maison","price":"13.00€"},{"name":"Verre de Mezcal sélection","price":"9.00€"},{"name":"Soda UMÀ Green Tea / Lemonade","price":"7.00€"}]}]}', '{"hero":"https://maps.googleapis.com/maps/api/place/photo?maxwidth=1600&photo_reference=ATCDNfWv5D-3u9G-O_vX-H4nK-R-nQ--jM--jM--jM--jM--jM--jM--jM--jM--jM--jM--jM--jM--jM--jM--jM--jM--jM--jM--jM--jM--jM--jM--jM--jM--jM--jM--jM--jM--jM--jM--jM--jM--jM--jM--jM--jM--jM--jM--jM--jM--jM--jM--jM--jM--jM--jM--jM--jM--jM--jM--jM--jM--jM--jM--jM--jM--jM--jM--jM--jM--jM--jM--jM--jM--jM--jM--jM--jM&key=AIzaSyDpkuHPvH-X8hZrLrpZbyC2Hi39iAfrLKM","gallery":[]}', '[]', NULL, '{"insider_tip":"Leur flan à l''huile d''olive et au romarin frit est devenu culte en quelques mois : ne terminez pas sans lui. Pour les amateurs de sensations fortes, demandez leur sélection de mezcals artisanaux.","specials":{"cuisine":["Modern Mexican (Norestense)","Cuisine de partage","Vins natures"],"drinks":["Mezcals de petits producteurs","Margaritas d''exception"],"must_eat":"Les Tacos de champignons sauvages et le Flan huile d''olive/romarin.","must_drink":"Une Margarita classique ou un verre de skin-contact wine."},"expert_catchline":"La cantina mexicaine 2.0 : saveurs explosives, ambiance tamisée et vins natures."}', 'Tarántula est la nouvelle sensation mexicaine de la rue Keller. Sous la houlette du chef Emmanuel Peña Treviño, cette cantina moderne délaisse les clichés pour proposer une cuisine du nord du Mexique (Norestense) hautement créative. Ambiance tamisée à la bougie, playlist pointue et sélection de vins natures : c''est le lieu parfait pour une soirée vibrante où les saveurs de piments fumés rencontrent des produits de terroir français sourcés avec soin.', 'Leur flan à l''huile d''olive et au romarin frit est devenu culte en quelques mois : ne terminez pas sans lui. Pour les amateurs de sensations fortes, demandez leur sélection de mezcals artisanaux.', 'Voltaire', '[9]', '[]', 'ChIJN4EGozVz5kcRcL9OSHhiPWE', NULL);
INSERT INTO places_fts VALUES ('poi-tarantula', 'Tarántula', 'restaurant', 'mexican cantina modern natural-wine', '13 bis Rue Keller', '', 'Tarántula est la nouvelle sensation mexicaine de la rue Keller. Sous la houlette du chef Emmanuel Peña Treviño, cette cantina moderne délaisse les clichés pour proposer une cuisine du nord du Mexique (Norestense) hautement créative. Ambiance tamisée à la bougie, playlist pointue et sélection de vins natures : c''est le lieu parfait pour une soirée vibrante où les saveurs de piments fumés rencontrent des produits de terroir français sourcés avec soin.');
