INSERT INTO places_fts VALUES ('poi-l-ebauchoir', 'L''Ébauchoir', 'restaurant', '', '43-45 Rue de Cîteaux, 75012 Paris, France', '', 'L''Ébauchoir est un bistrot d''une authenticité rare qui fait vibrer le quartier d''Aligre depuis des décennies. Sous les lustres d''époque et dans une ambiance indétrônable de brasserie parisienne, on y savoure une cuisine qui respecte les saisons avec une exigence de produit admirable. Son gâteau de riz est une légende locale que les habitués commandent avant même de regarder la carte. Précis, généreux et constant, c''est l''essence même du bien-manger parisien.');
