INSERT INTO places_fts VALUES ('poi-le-poisson-d-aligre', 'Le poisson d''Aligre', 'restaurant', '', 'Marché Beauvau, Pl. d''Aligre, 75012 Paris, France', '', 'Le Poisson d''Aligre (ou La Table d''Aligre) est une escale iodée incontournable sur la Place d''Aligre. Sous une devanture bleu marine sobre se cache un restaurant qui ne jure que par la fraîcheur absolue, avec des arrivages directs de Bretagne. Ici, le produit est roi et se déguste simplement, sublimé par une cuisson à la plancha millimétrée. L''ambiance est feutrée, le service impeccable, idéal pour savourer un Saint-Pierre ou un bar de ligne après avoir arpenté le marché voisin.');
