INSERT INTO places_fts VALUES ('poi-les-provinces-d-a-cote', 'Les Provinces d''à coté', 'restaurant', '', '20 Rue d''Aligre, 75012 Paris, France', '', 'Les Provinces d''à côté est une véritable ambassade de la viande située au cœur du marché d''Aligre. Mi-boucherie traditionnelle, mi-table d''hôte, le lieu propose une expérience radicale : choisir sa pièce de viande directement dans l''étal du boucher pour la faire griller à la perfection quelques mètres plus loin. Sous les carcasses suspendues et dans une odeur enivrante de jus de viande, on y redécouvre le goût du vrai produit dans une ambiance conviviale et sans artifice. Un incontournable pour les puristes carnivores.');
