INSERT INTO places_fts VALUES ('poi-anco', 'ANCO', 'restaurant', '', '108 Rue de Bercy, 75012 Paris, France', '', 'Anco est une adresse audacieuse nichée entre Bercy et la Gare de Lyon, offrant un cadre industriel et chaleureux. Le chef y propose une cuisine bistronomique de saison, précise et créative, où les produits du terroir sont sublimés par des techniques modernes. Avec sa cuisine ouverte et sa sélection de vins pointue, c''est l''endroit idéal pour un dîner élégant avant un spectacle à l''Accor Arena ou pour un déjeuner d''affaires raffiné.');
