INSERT INTO places_fts VALUES ('poi-chez-gino-pizza-feu-de-bois', 'Chez Gino Pizza Feu de Bois', 'restaurant', '', '80 Rue Dunois, 75013 Paris, France', '', 'Chez Gino est une adresse de référence pour les amoureux de la pizza authentique dans le 13ème arrondissement. Installé depuis des années rue Dunois, l''établissement mise sur une cuisson parfaite au feu de bois et des produits importés directement d''Italie. Une ambiance de quartier chaleureuse et sans superflu.');
