INSERT INTO places_fts VALUES ('poi-imperial-choisy', 'Impérial Choisy 美丽都', 'restaurant', '', '32 Av. de Choisy, 75013 Paris, France', '', 'L''Impérial Choisy est une institution incontournable pour les amateurs de rôtisserie cantonaise. Réputé pour son porc laqué Charsiu et son canard rôti d''une tendreté exemplaire, le restaurant offre une expérience authentique dans un cadre simple et efficace. Un pilier du quartier depuis des décennies.');
