) car la file d''attente s''allonge très vite sur le trottoir.
INSERT INTO places_fts VALUES ('poi-le-bambou', 'Le Bambou', 'restaurant', '', '70 Rue Baudricourt, 75013 Paris, France', '', 'Le Bambou est une véritable institution du quartier chinois de Paris. Reconnu pour son Phở légendaire et son ambiance de cantine vrombissante, c''est l''adresse de référence pour ceux qui cherchent l''authenticité vietnamienne sans fioritures. Service ultra-rapide et saveurs percutantes garanties.');
