INSERT INTO places_fts VALUES ('poi-pepe-rosso', 'Pépé Rosso', 'restaurant', 'trattoria', '77 Rue de la Glacière, 75013 Paris, France', '', 'Pépé Rosso est une trattoria familiale nichée au cœur du quartier de la Glacière. Reconnue pour sa cuisine italienne généreuse et ses recettes traditionnelles exécutées sans fioritures, c''est l''adresse idéale pour retrouver le goût de l''Italie dans une ambiance intimiste. Les pâtes y sont al dente et l''accueil toujours souriant.');
