f8IQqRgyJGLmPiCR2JtzqE1QUID_85Utj9OqQg6ZvFEFtWtiF0bCZARNPfcfgSjUGrQTyUs9HcSFypWvFjeBBuN77Mc4k7zkU-zLDND6_g2U1Fk4V4ML1QnuBRPKWZOG7oSVEj2yPUx5nZDDQ&key=AIzaSyDpkuHPvH-X8hZrLrpZbyC2Hi39iAfrLKM"]', NULL, '{"insider_tip":"Le menu déjeuner est un secret de quartier d''un rapport qualité-prix bluffant. Ne passez pas à côté de l''oeuf parfait, une signature de la maison exécutée avec une maîtrise parfaite.","specials":{"cuisine":["Bistronomique Moderne","Cuisine du Marché"],"drinks":["Sélection de Vins de Propriété","Digestifs Artisanaux"],"must_eat":"L''Oeuf Parfait et la Joue de Boeuf confite.","must_drink":"Un vin blanc sec de Loire pour accompagner le poisson."},"expert_catchline":"La bistronomie d''une précision chirurgicale au cœur du 14ème."}', 'L''Ordonnance est un joyau bistronomique niché discrètement rue des Plantes. Ici, la cuisine est une affaire de précision et de respect absolue du produit. Le chef propose une carte courte qui change au gré des saisons et des arrivages du marché, garantissant une fraîcheur irréprochable. Le cadre est élégant sans être guindé, avec une atmosphère calme et intimiste qui se prête merveilleusement aux conversations. C''est l''adresse de quartier par excellence pour les amateurs de gastronomie française moderne et raffinée.', 'Le menu déjeuner est un secret de quartier d''un rapport qualité-prix bluffant. Ne passez pas à côté de l''oeuf parfait, une signature de la maison exécutée avec une maîtrise parfaite.', 'Alésia', '["4"]', '[]', 'ChIJZRqAdbpx5kcRnEoHtO5qUnI', NULL);
INSERT INTO places_fts VALUES ('poi-ordonnance-75014', 'L''Ordonnance', 'restaurant', 'bistronomie contemporain raffiné marché intimiste', '51 Rue des Plantes, 75014 Paris, France', '', 'L''Ordonnance est un joyau bistronomique niché discrètement rue des Plantes. Ici, la cuisine est une affaire de précision et de respect absolue du produit. Le chef propose une carte courte qui change au gré des saisons et des arrivages du marché, garantissant une fraîcheur irréprochable. Le cadre est élégant sans être guindé, avec une atmosphère calme et intimiste qui se prête merveilleusement aux conversations. C''est l''adresse de quartier par excellence pour les amateurs de gastronomie française moderne et raffinée.');
