INSERT INTO places_fts VALUES ('poi-petits-parisiens-75014', 'Les Petits Parisiens', 'restaurant', 'bistronomie moderne terroir institution cosy', '33 Avenue Jean Moulin, 75014 Paris, France', '', 'Les Petits Parisiens est le digne successeur de l''esprit Régalade sur l''avenue Jean Moulin. Repris avec brio, ce bistrot chic propose une cuisine d''auteur signée Arnaud Baptiste, qui allie avec maestria les codes de la grande cuisine bourgeoise et une modernité décomplexée. Le cadre est élégant, avec ses banquettes de velours et son éclairage tamisé, créant un cocon idéal pour savourer des assiettes d''une grande justesse. C''est le nouveau repaire des gourmets du sud parisien en quête de sincérité culinaire.');
