INSERT INTO places_fts VALUES ('poi-baladna', 'Baladna', 'restaurant', 'libanais méditerranéen grillades mezzés restaurant', '26 Pl. Denfert-Rochereau, 75014 Paris', '', 'Surplombant la place Denfert-Rochereau, Baladna est une escale libanaise authentique qui refuse les compromis sur la qualité. Ici, les mezzés sont faits maison tous les matins et les grillades au feu de bois embaument la salle. L''ambiance est familiale, généreuse et invite au voyage culinaire entre Beyrouth et Paris. Une valeur sûre pour découvrir la finesse d''un vrai houmous et la tendreté des viandes marinées.');
