e/photo?maxwidth=1600&photo_reference=ATCDNfXL0-5sbpYusfBsXLHeiWhLJ60QTM9tJomin9wIWiKaWMofjB_QzY4GABYn92QSZNAsf-fpQ8tMaKnldJ4rZbuetw4ljaS3otnWCTbJAFVGjDfBhC3-KbuKfnoRa5U-W7U6lK5WhVLh0AuxkymXvuocjOAgFG1gFIHQpzUA1SpRgl8qDGTcIHGSpQN0aCZIlDg-lj7BRsjVcI32YnhNBF8zCLkxDxVxZJLrOf7qtYGTxd2GabRHcZ4EaYHRFY4fssIAh1fSpQSrJsWuykovbwMFTSwJCIaWNvXbZwmjVtexq00vXEhstClvV8PE24JEiTFO1IEMaaSOnnbheQLlxMpcxUHXhioZ0wiRzvqu9Yr9Y1xFYdWuzS9-JtWhJ3OV6MW4gNeuKY88wh4541ZxBz_f-Yq52hda1AGWtyORDHeOkqixkhPetZ6k4UCESQ&key=AIzaSyDpkuHPvH-X8hZrLrpZbyC2Hi39iAfrLKM"]', NULL, '{"insider_tip":"C''est l''endroit parfait pour un dîner romantique ou confidentiel loin de l''agitation de Denfert-Rochereau. La terrine maison est un modèle du genre, généreuse et goûteuse.","specials":{"cuisine":["Bistrot Traditionnel","Cuisine Familiale"],"drinks":["Sélection de Vignerons","Vins de Pays"],"must_eat":"La cuisse de canard confite et la tarte Tatin.","must_drink":"Un verre de vin rouge gouleyant sélectionné par l''équipe."},"expert_catchline":"L''intimité du vrai bistrot parisien près de Denfert."}', 'Niché dans la calme rue Lalande, Au Bistrot d''à Côté est le type même du bistrot de charme dont Paris a le secret. Avec sa devanture rouge et son intérieur boisé, c''est une adresse qui cultive l''intimité et la sincérité. Le chef y propose une cuisine de terroir sans artifice, où le goût du produit brut est respecté, le tout servi avec une bienveillance qui fait du bien.', 'C''est l''endroit parfait pour un dîner romantique ou confidentiel loin de l''agitation de Denfert-Rochereau. La terrine maison est un modèle du genre, généreuse et goûteuse.', 'Denfert-Rochereau', '[4,6,"B"]', '[]', 'ChIJndbsU7Zx5kcRT-RfPHpe1Zo', NULL);
INSERT INTO places_fts VALUES ('poi-bistrot-a-cote', 'Au Bistrot d''à Côté', 'restaurant', 'bistrot terroir charme traditionnel', '18 Rue Lalande', '', 'Niché dans la calme rue Lalande, Au Bistrot d''à Côté est le type même du bistrot de charme dont Paris a le secret. Avec sa devanture rouge et son intérieur boisé, c''est une adresse qui cultive l''intimité et la sincérité. Le chef y propose une cuisine de terroir sans artifice, où le goût du produit brut est respecté, le tout servi avec une bienveillance qui fait du bien.');
INSERT INTO places VALUES ('poi-cafe-rendez-vous', 'Café du Rendez-Vous', 'cafe-rendez-vous', 'restaurant', 'brasserie, bistronomie, terrasse, institution', 'chill', 48.834141, 2.332309, 14, '2 Av. du Général Leclerc', '#8ccaf7', 'pin', 1, 4, 0, 'https://maps.googleapis.com/maps/api/place/photo?maxwidth=1600&photo_reference=Aaw_79J-8v8v8v8v8v8v8v8v8v8v8v8v8v8v8v8v&key=AIzaSyDpkuHPvH-X8hZrLrpZbyC2Hi39iAfrLKM', NULL, 19.5, 0, '€', 9, NULL, 7, 2.8, 19.5, 50, '{"chill":80,"festif":30,"culturel":20}', '{}', '["restaurant","brasserie","bistronomie","terrasse","institution"]', '{"standard":"Lundi-Dimanche: 07:00–02:00","display":"Lundi-Dimanche: 07:00–02:00","detailed":"Lundi-Dimanche: 07:00–02:00"}', '{"opening_hours_raw":"Lundi-Dimanche: 07:00–02:00","reservation_policy":"sans_resa","terrace":true,"accessibility":true,"wifi":true,"main_action":{"type":"site","url":"https://www.lecafedurendezvous.com/","label":"SITE OFFICIEL"},"happy_hour":null}', '{"avg_budget":35,"is_free":false,"pint_price":9,"wine_glass":7,"coffee_price":2.8,"dish_price":19.5,"menu_type":"standard","last_updated":"2026-03-10","menu_items":[{"category":"Bistronomie de Saison","items":[{"name":"Blanquette de veau à l''ancienne","price":"21.00€"},{"name":"Saucisse d''Auvergne & Aligot","price":"19.50€"},{"name":"Poisson frais du jour, riz aux herbes","price":"22.00€"},{"name":"Burger au Bleu d''Auvergne","price":"18.50€"},{"name":"Tartare de Bœuf boucher","price":"17.50€"}]},{"category":"Entrées & Tapas","items":[{"name":"Oeuf cocotte à la tomate confite","price":"11.50€"},{"name":"Asperges rôties au parmesan","price":"7.50€"},{"name":"Planche de tapas à partager","price":"18.00€"},{"name":"Soupe à l''oignon gratinée","price":"9.50€"}]},{"category":"Douceurs Maison","items":[{"name":"French Toast au caramel beurre salé","price":"9.00€"},{"name":"Tiramisu du Rendez-Vous","price":"8.50€"},{"name":"Île flottante généreuse","price":"7.50€"}]}]}', '{"hero":"https://maps.googleapis.com/maps/api/place/photo?maxwidth=1600&photo_reference=Aaw_79J-8v8v8v8v8v8v8v8v8v8v8v8v8v8v8v8v&key=AIzaSyDpkuHPvH-X8hZrLrpZbyC2Hi39iAfrLKM","gallery":["https://maps.googleapis.com/maps/api/place/photo?maxwidth=1600&photo_reference=Aaw_79K-8v8v8v8v8v8v8v8v8v8v8v8v8v8v8v8v&key=AIzaSyDpkuHPvH-X8hZrLrpZbyC2Hi39iAfrLKM","https://maps.googleapis.com/maps/api/place/photo?maxwidth=1600&photo_reference=Aaw_79L-8v8v8v8v8v8v8v8v8v8v8v8v8v8v8v8v&key=AIzaSyDpkuHPvH-X8hZrLrpZbyC2Hi39iAfrLKM"]}', '["https://maps.googleapis.com/maps/api/place/photo?maxwidth=1600&photo_reference=Aaw_79K-8v8v8v8v8v8v8v8v8v8v8v8v8v8v8v8v&key=AIzaSyDpkuHPvH-X8hZrLrpZbyC2Hi39iAfrLKM","https://maps.googleapis.com/maps/api/place/photo?maxwidth=1600&photo_reference=Aaw_79L-8v8v8v8v8v8v8v8v8v8v8v8v8v8v8v8v&key=AIzaSyDpkuHPvH-X8hZrLrpZbyC2Hi39iAfrLKM"]', NULL, '{"insider_tip":"Profitez du Happy Hour de 17h à 21h pour découvrir leurs planches de tapas à prix doux. La terrasse est chauffée en hiver, ce qui en fait l''un des rares spots confortables dehors toute l''année à Denfert.","specials":{"cuisine":["Bistronomie Saisonnière","Happy Hour"],"drinks":["Cocktails Premium","Bière de spécialité"],"must_eat":"L''œuf cocotte maison et le French Toast au caramel.","must_drink":"Une bière artisanale ou un cocktail signature en terrasse."},"expert_catchline":"La terrasse institutionnelle et conviviale de Denfert."}', 'Le Café du Rendez-Vous est l''âme battante de la Place Denfert-Rochereau. Depuis plus de 30 ans, cette brasserie tenue par la famille Porte incarne le trait d''union parfait entre le bistrot parisien traditionnel et l''élégance contemporaine. Sa terrasse chauffée et vitrée, véritable poste d''observation sur le mouvement de la ville, ne désemplit jamais, du petit-déjeuner matinal au dernier cocktail de la nuit.', 'Profitez du Happy Hour de 17h à 21h pour découvrir leurs planches de tapas à prix doux. La terrasse est chauffée en hiver, ce qui en fait l''un des rares spots confortables dehors toute l''année à Denfert.', 'Denfert-Rochereau', '[4,6,"B"]', '[]', 'ChIJEYElfrdx5kcR8NJ6jn7CDG8', NULL);
INSERT INTO places_fts VALUES ('poi-cafe-rendez-vous', 'Café du Rendez-Vous', 'restaurant', 'brasserie bistronomie terrasse institution', '2 Av. du Général Leclerc', '', 'Le Café du Rendez-Vous est l''âme battante de la Place Denfert-Rochereau. Depuis plus de 30 ans, cette brasserie tenue par la famille Porte incarne le trait d''union parfait entre le bistrot parisien traditionnel et l''élégance contemporaine. Sa terrasse chauffée et vitrée, véritable poste d''observation sur le mouvement de la ville, ne désemplit jamais, du petit-déjeuner matinal au dernier cocktail de la nuit.');
