de sensations fortes.', 'Gaité', '["13"]', '[]', 'ChIJlaEwLn9x5kcRLsh7q_LCDkM', NULL);
INSERT INTO places_fts VALUES ('poi-tripletta-gaite-75014', 'Tripletta Gaité', 'restaurant', 'pizza italien vibrant terrasse napolitain', '1 Impasse de la Gaité, 75014 Paris, France', '', 'Tripletta Gaité est l''ambassade de la pizza napolitaine dans le quartier de la Gaité. Avec son four à bois imposant et sa décoration industrielle chaleureuse, le lieu dégage une énergie vibrante dès l''entrée. La pâte, longuement maturée, est une merveille de légèreté et de moelleux, garnie de produits sourcés directement en Italie. La terrasse, située dans une petite impasse calme, est une pépite rare dans ce quartier animé. C''est l''adresse idéale pour une pizza entre amis avant une séance de théâtre.');
