rvis ici dans leur version la plus traditionnelle : n''hésitez pas à demander du piment frais supplémentaire pour un kick authentique.
INSERT INTO places_fts VALUES ('poi-hanoi-quan', 'Hanoi Quan', 'restaurant', 'vietnamien pho bo-bun cantine authentique', '2 Place de Catalogne, 75014 Paris, France', '', 'Trônant sur la Place de Catalogne, Hanoi Quan est une escale vietnamienne authentique qui réchauffe le quartier Montparnasse. Son bouillon Phở, mijoté pendant des heures, et ses Bo Bun généreux en font une adresse incontournable pour les amateurs de saveurs du Mékong. L''ambiance y est décontractée, idéale pour un shoot de fraîcheur avant de prendre un train.');
