INSERT INTO places_fts VALUES ('poi-mr-chow', 'MR CHOW', 'restaurant', 'hongkongaise chinois cantonais noodles panda-panda', '12 Rue Delambre, 75014 Paris, France', '', 'MR CHOW est l''escale hongkongaise immersive du groupe Panda Panda à Montparnasse. Dans un décor haché inspiré du Hong Kong des années 60 (façon In the Mood for Love), on y déguste une cuisine chinoise traditionnelle faite maison, généreuse et vibrante.');
