VVDOIwWw3WAGPhgNJ87mSM7FPhn_hw3kEzAkVQ5ywTp0wj9J6E7ZSJFBDGHCupYScfxmspWY0ty-jeOfftwGzNhhzzmHgeLB_OFWolDI_iapyS2cRS7Jye8DTWra4lkiGkRekQtPg7fDlt10TsxfXvAbm_gKOYU6Obpos7oOCpXD16uwkO4YKnYSn66V_Pr6IbJYebr5ILNWuU95z_fC9xJ_XrZd6zSS1tfkGu3YJtlX4UThDjqMY5B8H-nA8OPf_tUStQc917xp6UBGUB5KA8moSgBdxHFEE&key=AIzaSyDpkuHPvH-X8hZrLrpZbyC2Hi39iAfrLKM"]', NULL, '{"insider_tip":"La mousse au chocolat est un incontournable absolu, servie comme à la maison. Le midi, la formule du jour est d''un excellent rapport qualité-prix, très prisée des habitants du quartier.","specials":{"cuisine":["Bistrot Traditionnel","Cuisine Ménagère"],"drinks":["Vins au Verre","Bière de Brasserie"],"must_eat":"Le Confit de Canard et les Frites Maison.","must_drink":"Un quart de vin rouge de pays."},"expert_catchline":"La sincérité du bistrot parisien dans chaque assiette."}', 'Les Petits Plats, situé rue des Plantes, est l''archétype du bistrot parisien chaleureux et sincère. Ici, pas de chichis, mais une cuisine généreuse faite de produits frais et de saison. Le cadre est authentique, avec ses boiseries et ses ardoises affichant les suggestions du jour. On s''y sent tout de suite chez soi, accueilli par une équipe aux petits soins. C''est l''adresse parfaite pour un déjeuner réconfortant ou un dîner convivial entre amis autour de classiques français parfaitement exécutés.', 'La mousse au chocolat est un incontournable absolu, servie comme à la maison. Le midi, la formule du jour est d''un excellent rapport qualité-prix, très prisée des habitants du quartier.', 'Alésia', '["4"]', '[]', 'ChIJOZXq-7Jx5kcRr7k3qLJAwXM', NULL);
INSERT INTO places_fts VALUES ('poi-petits-plats-75014', 'Les Petits Plats', 'restaurant', 'bistrot terroir traditionnel chaleureux fait-maison', '39 Rue des Plantes, 75014 Paris, France', '', 'Les Petits Plats, situé rue des Plantes, est l''archétype du bistrot parisien chaleureux et sincère. Ici, pas de chichis, mais une cuisine généreuse faite de produits frais et de saison. Le cadre est authentique, avec ses boiseries et ses ardoises affichant les suggestions du jour. On s''y sent tout de suite chez soi, accueilli par une équipe aux petits soins. C''est l''adresse parfaite pour un déjeuner réconfortant ou un dîner convivial entre amis autour de classiques français parfaitement exécutés.');
