INSERT INTO places_fts VALUES ('poi-la-manifattura', 'La Manifattura', 'restaurant', 'italien pizzeria napolitain vins italiens restaurant', '106 Boulevard du Montparnasse, 75014 Paris', '', 'Championne de la pizza à Paris, La Manifattura est une escale incontournable sur le boulevard du Montparnasse pour les amateurs de pâte napolitaine d''exception. Le secret réside dans une fermentation longue du pâton et des produits importés directement de petits producteurs italiens. L''ambiance y est vivante, avec le four à bois en vedette et un service qui chante l''Italie.');
