kMFvjzPkF92qK6W3fFtcCfClY_VW0ReYHyQtkO87I6IS2yQP9URzkesiNRR_m5574_FmgOwe0s4LtXOo_Hex9GuaWuiJh7XSevIHjZPaOk3tsNuejWCLqIMMWoyeeU09xOTdziQIKe8AB_RKdTLRlNoCESXx1FqQeH2dB1CS_-Y-taqU1i__H3QxDTBoTC20ojkBWQANrEuUWlsYgv_MSOLNYIG0wmL3vJkiNoWUrVCrhGERNoflSz0JmCym7C-8w3OjVTWIhfeueHw"]', NULL, '{"insider_tip":"• **Timing Stratégique** : Arrivez tôt le soir pour voir le spectacle des poulets qui commencent leur rotation sur les broches.\n  • **Combo Moelle** : Le poulet rôti évidemment, accompagné de la purée monumentale, un duo inséparable.\n  • **Expérience Culturelle** : La rôtisserie apparente et les nappes à carreaux rouges créent une immersion immédiate dans le Paris éternel.","specials":{"cuisine":["Français","Rôtisserie","Tradition"],"drinks":["Vins du Beaujolais","Vins de Loire"],"must_eat":"Rôtisserie Traditionnelle. Le poulet fermier rôti à la broche et la purée maison."}}', 'La Retraite du Père Claude est une institution du 15e, célèbre pour sa cuisine de rôtisserie authentique et son ambiance de bistrot convivial. Sous l''œil bienveillant du chef Claude Perraudin, les poulets fermiers tournent sur de grandes broches verticales, embaumant la salle de parfums alléchants. La purée maison, onctueuse et généreuse, est devenue légendaire tout comme les escargots de Bourgogne et le boudin noir maison. C''est l''adresse idéale pour un repas réconfortant dans un cadre chaleureux et sans chichis.', '• **Timing Stratégique** : Arrivez tôt le soir pour voir le spectacle des poulets qui commencent leur rotation sur les broches.
INSERT INTO places_fts VALUES ('poi-la-retraite-du-pere-claude', 'La Retraite du Père Claude', 'restaurant', '', '89 Rue de la Convention, 75015 Paris, France', '', 'La Retraite du Père Claude est une institution du 15e, célèbre pour sa cuisine de rôtisserie authentique et son ambiance de bistrot convivial. Sous l''œil bienveillant du chef Claude Perraudin, les poulets fermiers tournent sur de grandes broches verticales, embaumant la salle de parfums alléchants. La purée maison, onctueuse et généreuse, est devenue légendaire tout comme les escargots de Bourgogne et le boudin noir maison. C''est l''adresse idéale pour un repas réconfortant dans un cadre chaleureux et sans chichis.');
