9,00€","description":"Version relevée avec ail et persil."},{"name":"Hommos Viande","price":"10,50€","description":"Relevé avec des émincés de viande poêlés."},{"name":"Moutabal (Caviar d''aubergine)","price":"8,00€","description":"Aubergine grillée, crème de sésame."},{"name":"Taboulé Libanais","price":"8,00€","description":"Persil, blé concassé, tomate, menthe, oignon, citron."}]},{"category":"Mezzés Chauds","items":[{"name":"Falafels (4 pièces)","price":"8,40€","description":"Boulettes frites de fèves et pois chiches."},{"name":"Kebbé Boulettes (4 pièces)","price":"8,40€","description":"Viande farcie au bourghoul et pignons de pin."}]},{"category":"Grillades & Assiettes","items":[{"name":"Chawarma (Bœuf mariné)","price":"25,00€","description":"Sur place. Viande de bœuf mariné, émincé et grillé."},{"name":"Chiche Taouk (Poulet mariné)","price":"23,50€"},{"name":"Sandwich Chawarma (Emporter)","price":"7,50€"}]},{"category":"Boissons & Vins","items":[{"name":"Verre de Vin Ksara Libanais","price":"8,00€"},{"name":"Arak (Boisson libanaise anisée 8cl)","price":"7,00€"},{"name":"Bière Libanaise (33cl)","price":"6,00€"},{"name":"Laban Ayran (Yaourt liquide salé)","price":"6,00€"},{"name":"Café Expresso","price":"2,60€"},{"name":"Café Blanc (Eau de fleur d''oranger)","price":"3,80€"}]}],"last_updated":"2026-03-04"}', '{"hero":"https://maps.googleapis.com/maps/api/place/photo?maxwidth=1600&photo_reference=ATCDNfWCsAyKbgKYjzQEdXDkqECSzhq_4p847-EJQ7T2xaSR8eBbqe9Vnll8MFuj8iGMvdtc4scI9794DkJ4yjeipSiBRAHMOEewSV8qMv2EeoKF_R7ChcvOsEqaXk-jB2DUSdxLB_VwGz2VcXaZDavYiJIrVyEITMuC_SzLc2JRxE_kc3UKqUnoEGX0Gl8ZZzILudeQeMbgA--eCyHmlZ6hUwP1KNHElv-YJac7thSctx4mEuvfoYvaJYpdkAqcB16ix8xxda7y04pB8fd1P1Y-UNRtkuHI4UrPM5CAbzhfPpdo2w&key=AIzaSyDpkuHPvH-X8hZrLrpZbyC2Hi39iAfrLKM","gallery":["https://maps.googleapis.com/maps/api/place/photo?maxwidth=1600&photo_reference=ATCDNfVR0_a2BXnuJqHPGyZlxfjUj6z1EwMDabfysv_8d4pywEq_Cdanftns7qtZNRWjbZ6SSuiKDIHQMcxy6FecFwNq5PpNLacXNEKriqjWnbt7A6Pm0Ix4vKNKmVT39CvO9An