 tables en terrasse très convoitées.
INSERT INTO places_fts VALUES ('poi-le-17-45', 'Le 17.45 Batignolles', 'restaurant', 'Planches à composer Bar à vin Apéro', '45 Rue des Dames, 75017 Paris, France', '', 'Le 17.45 est le spécialiste des planches à composer selon vos envies. Situé dans la vivante Rue des Dames aux Batignolles, ce lieu est devenu le repaire incontournable des amateurs d''apéro dînatoire. On y choisit ses fromages et ses charcuteries à la pièce sur une fiche de commande, le tout provenant de petits producteurs passionnés. L''ambiance est jeune, décontractée et souvent très animée en fin de semaine.');
