'• **Timing Stratégique** : Arrivez 15 minutes avant l''ouverture de la session du soir (18h15) pour espérer avoir une table sans trop d''attente (pas de résa).
INSERT INTO places_fts VALUES ('poi-mamma-primi', 'Mamma Primi', 'restaurant', 'Italien Pizza Trattoria', '18 Rue Boursault, 75017 Paris, France', '', 'Mamma Primi est la déclinaison florale et chaleureuse du groupe Big Mamma aux Batignolles. Entre les suspensions de fleurs séchées et la vaisselle colorée chinée en Italie, on y sert une cuisine généreuse faite maison. Le spot parfait pour une soirée festive entre amis autour d''une pile de pizzas au feu de bois et de cocktails italiens.');
