INSERT INTO places VALUES ('poi-205', 'Bloom', 'bloom-cafe', 'café', 'healthy-cafe', 'chill', 48.881949, 2.301809, 17, '99 Rue Jouffroy d''Abbans', '#8ccaf7', 'pin', 1, 4.5, 0, 'https://maps.googleapis.com/maps/api/place/photo?maxwidth=1600&photoreference=AcnlKN2LYNSBYNgim2bagNnvfGQk2FHz1HUwVn-7NAoQhEheGur6R271QH9rK_RAQ_qzae6Pm37v7mH7JyAJf5WXJQhk90pa0ZawDzjYja5WITIDS1tVJ_gNISG4FlSSOyPUNxIEqjyRCTUvv_Xw-t0_UNifpXOxz4PGizR1ARwV6bFWfWx8g8OobdlgXH5twJfX0U5CemHSaKaVZPOgS2PuFiGriz_snUDivo7MoM8-X6A7OimtigagpadfRk_Z2TU_ccljXz9o1aKjQAbnYAv69FXIB_pyJC8opqMENx6zASeDuw&key=AIzaSyDpkuHPvH-X8hZrLrpZbyC2Hi39iAfrLKM', NULL, 4.5, 0, '€', NULL, NULL, NULL, 4.5, 0, 50, '{"chill":23,"festif":4,"culturel":5}', '{}', '["café","healthy-cafe"]', '{"standard":"","display":"","detailed":""}', '{"reservation_policy":null,"accessibility":false,"wifi":false,"opening_hours_raw":"","action_type":"site","action_url":"","terrace":false,"happy_hour":null}', '{"avg_budget":16,"is_free":false,"pint_price":0,"cocktail_price":0,"coffee_price":4.5,"dish_price":0,"menu_items":[]}', '{"hero":"https://maps.googleapis.com/maps/api/place/photo?maxwidth=1600&photoreference=AcnlKN2LYNSBYNgim2bagNnvfGQk2FHz1HUwVn-7NAoQhEheGur6R271QH9rK_RAQ_qzae6Pm37v7mH7JyAJf5WXJQhk90pa0ZawDzjYja5WITIDS1tVJ_gNISG4FlSSOyPUNxIEqjyRCTUvv_Xw-t0_UNifpXOxz4PGizR1ARwV6bFWfWx8g8OobdlgXH5twJfX0U5CemHSaKaVZPOgS2PuFiGriz_snUDivo7MoM8-X6A7OimtigagpadfRk_Z2TU_ccljXz9o1aKjQAbnYAv69FXIB_pyJC8opqMENx6zASeDuw&key=AIzaSyDpkuHPvH-X8hZrLrpZbyC2Hi39iAfrLKM","gallery":[]}', '[]', NULL, '{"insider_tip":"L''adresse préférée des locaux, loin des foules habituelles.","specials":{"cuisine":[],"drinks":[]}}', 'Bloom Café est la pause zen et healthy des Batignolles. Un lieu baigné de lumière, décoré de plantes et de bois clair, où l''on vient pour un brunch de qualité servi tous les jours. Avocado toasts impeccables, acaï bowls colorés et cafés de spécialité composent une carte qui fait du bien au corps et à l''esprit. C''est l''endroit parfait pour se poser avec un livre ou discuter tranquillement entre deux rendez-vous, dans une atmosphère douce et résolument contemporaine.', 'L''adresse préférée des locaux, loin des foules habituelles.', 'À proximité', '[]', '[]', NULL, NULL);
INSERT INTO places_fts VALUES ('poi-205', 'Bloom', 'café', 'healthy-cafe', '99 Rue Jouffroy d''Abbans', '', 'Bloom Café est la pause zen et healthy des Batignolles. Un lieu baigné de lumière, décoré de plantes et de bois clair, où l''on vient pour un brunch de qualité servi tous les jours. Avocado toasts impeccables, acaï bowls colorés et cafés de spécialité composent une carte qui fait du bien au corps et à l''esprit. C''est l''endroit parfait pour se poser avec un livre ou discuter tranquillement entre deux rendez-vous, dans une atmosphère douce et résolument contemporaine.');
INSERT INTO places VALUES ('poi-206', 'Dose Batignolles', 'dose-batignolles', 'café', 'specialty-coffee', 'chill', 48.88709, 2.317899, 17, '82 Place du Dr Félix Lobligeois', '#8ccaf7', 'pin', 1, 4.7, 0, 'https://maps.googleapis.com/maps/api/place/photo?maxwidth=1600&photoreference=AcnlKN34jHK8_P_H22FdoEAjddqDfZLDhKbKYJomic7e4-Iem6y42LpzMcEuM5Vbm8ujYwXnJNakwyCOlrMCQIT5YnvSDcEFXCdOaEFfHM3JprZgd16JkD-w13b7OiW5bzXQtWTdnnUzAwXp-3vqGDRBW-0LDyUsFUKNWtcrCbf8qfH9WkXZyxtySCZkBudi2aORu2a4G6RmP8YfY3RU4v7YVmtsDlRANpcjw6aJeVtml_jg022BrhEs7GKFdvuv5teemR-CieOfZpDoLJ3wrOnKCj5p0Htn2KFrUwKoLOoLKmjCWQ&key=AIzaSyDpkuHPvH-X8hZrLrpZbyC2Hi39iAfrLKM', NULL, 3.5, 0, '€', NULL, NULL, NULL, 3.5, 0, 50, '{"chill":23,"festif":4,"culturel":5}', '{}', '["café","specialty-coffee"]', '{"standard":"","display":"","detailed":""}', '{"reservation_policy":null,"accessibility":false,"wifi":false,"opening_hours_raw":"","action_type":"site","action_url":"","terrace":false,"happy_hour":null}', '{"avg_budget":15,"is_free":false,"pint_price":0,"cocktail_price":0,"coffee_price":3.5,"dish_price":0,"menu_items":[]}', '{"hero":"https://maps.googleapis.com/maps/api/place/photo?maxwidth=1600&photoreference=AcnlKN34jHK8_P_H22FdoEAjddqDfZLDhKbKYJomic7e4-Iem6y42LpzMcEuM5Vbm8ujYwXnJNakwyCOlrMCQIT5YnvSDcEFXCdOaEFfHM3JprZgd16JkD-w13b7OiW5bzXQtWTdnnUzAwXp-3vqGDRBW-0LDyUsFUKNWtcrCbf8qfH9WkXZyxtySCZkBudi2aORu2a4G6RmP8YfY3RU4v7YVmtsDlRANpcjw6aJeVtml_jg022BrhEs7GKFdvuv5teemR-CieOfZpDoLJ3wrOnKCj5p0Htn2KFrUwKoLOoLKmjCWQ&key=AIzaSyDpkuHPvH-X8hZrLrpZbyC2Hi39iAfrLKM","gallery":[]}', '[]', NULL, '{"insider_tip":"L''adresse préférée des locaux, loin des foules habituelles.","specials":{"cuisine":[],"drinks":[]}}', 'Dose est bien plus qu''un simple café, c''est l''antre des puristes du grain aux Batignolles. Installé face au parc, ce coffee shop propose une torréfaction propre et une expertise rare sur chaque tasse. Du V60 au Flat White, chaque extraction est une leçon de goût. L''ambiance y est cool et studieuse, complétée par une offre de brunch gourmande et des jus frais pressés minute. C''est l''essence même du ''third wave coffee'' appliqué avec passion dans un cadre de quartier chaleureux.', 'L''adresse préférée des locaux, loin des foules habituelles.', 'À proximité', '[]', '[]', NULL, NULL);
INSERT INTO places_fts VALUES ('poi-206', 'Dose Batignolles', 'café', 'specialty-coffee', '82 Place du Dr Félix Lobligeois', '', 'Dose est bien plus qu''un simple café, c''est l''antre des puristes du grain aux Batignolles. Installé face au parc, ce coffee shop propose une torréfaction propre et une expertise rare sur chaque tasse. Du V60 au Flat White, chaque extraction est une leçon de goût. L''ambiance y est cool et studieuse, complétée par une offre de brunch gourmande et des jus frais pressés minute. C''est l''essence même du ''third wave coffee'' appliqué avec passion dans un cadre de quartier chaleureux.');
INSERT INTO places VALUES ('poi-213', 'Le Bal', 'le-bal-paris', 'museum', 'espace-culturel', 'culturel', 48.885278, 2.327355, 17, '6 Imp. de la Défense', '#c499ff', 'pin', 1, 4.5, 0, 'https://maps.googleapis.com/maps/api/place/photo?maxwidth=1600&photoreference=AcnlKN1dYALkmbH1Vr19ct8bF6ws3XnS1ObuUI97VoMDA3sbdwSv97fmE5COMatN2u2P5RdKNN7lULYrfENnbXTdW702P8szlZSDDUo8tT9yhv7bhDIgrwfELIgB3el7IdcPP3gcvfBApA6OPV5uVOFeoTQeYWn22VkpoaEHzPmaA-AoHviyCHFSPsHAmTygjaJKWTR3PcZNizVNjKzcTJUdtmgmwrcIGrQ866qA_OjX6swTaUeFI15-PqEp8JPdRQYH5q2Tnnn0ns5Pk7ttgJNFMzGQzMGFzQVb0FlxM_7nT5c6hg&key=AIzaSyDpkuHPvH-X8hZrLrpZbyC2Hi39iAfrLKM', NULL, 15, 0, '€', NULL, NULL, NULL, 0, 0, 50, '{"chill":6,"festif":4,"culturel":24}', '{}', '["museum","espace-culturel"]', '{"standard":"","display":"","detailed":""}', '{"reservation_policy":null,"accessibility":false,"wifi":false,"opening_hours_raw":"","action_type":"site","action_url":"","terrace":false,"happy_hour":null}', '{"index_price":15,"avg_budget":8,"is_free":false,"pint_price":0,"cocktail_price":0,"coffee_price":0,"dish_price":0,"menu_items":[]}', '{"hero":"https://maps.googleapis.com/maps/api/place/photo?maxwidth=1600&photoreference=AcnlKN1dYALkmbH1Vr19ct8bF6ws3XnS1ObuUI97VoMDA3sbdwSv97fmE5COMatN2u2P5RdKNN7lULYrfENnbXTdW702P8szlZSDDUo8tT9yhv7bhDIgrwfELIgB3el7IdcPP3gcvfBApA6OPV5uVOFeoTQeYWn22VkpoaEHzPmaA-AoHviyCHFSPsHAmTygjaJKWTR3PcZNizVNjKzcTJUdtmgmwrcIGrQ866qA_OjX6swTaUeFI15-PqEp8JPdRQYH5q2Tnnn0ns5Pk7ttgJNFMzGQzMGFzQVb0FlxM_7nT5c6hg&key=AIzaSyDpkuHPvH-X8hZrLrpZbyC2Hi39iAfrLKM","gallery":[]}', '[]', NULL, '{"insider_tip":"L''entrée est gratuite tous les premiers dimanches du mois.","specials":{"cuisine":[],"drinks":[]}}', 'LE BAL est un carrefour culturel indépendant dédié à l''image documentaire sous toutes ses formes (photo, film, livre). Installé dans une ancienne salle de bal des années Folles au fond d une impasse, le lieu dégage une énergie créative et exigeante. On y vient pour découvrir des expositions pointues et souvent inédites, ou pour flâner dans l une des meilleures librairies photographiques de Paris. C''est un lieu vibrant, qui invite à la réflexion et à la contemplation de notre monde à travers l objectif.', 'L''entrée est gratuite tous les premiers dimanches du mois.', 'À proximité', '[]', '[]', NULL, NULL);
INSERT INTO places_fts VALUES ('poi-213', 'Le Bal', 'museum', 'espace-culturel', '6 Imp. de la Défense', '', 'LE BAL est un carrefour culturel indépendant dédié à l''image documentaire sous toutes ses formes (photo, film, livre). Installé dans une ancienne salle de bal des années Folles au fond d une impasse, le lieu dégage une énergie créative et exigeante. On y vient pour découvrir des expositions pointues et souvent inédites, ou pour flâner dans l une des meilleures librairies photographiques de Paris. C''est un lieu vibrant, qui invite à la réflexion et à la contemplation de notre monde à travers l objectif.');
