://www.larughetta.com/fr/","label":"SITE OFFICIEL"},"happy_hour":null}', '{"avg_budget":29,"is_free":false,"pint_price":0,"cocktail_price":0,"wine_glass":7,"coffee_price":2.5,"dish_price":14,"last_updated":"2026-03-05","menu_items":[{"category":"Antipasti","items":[{"name":"Insalata Tricolore","price":"4.00€"},{"name":"Tomates Mozzarella di Bufala","price":"7.00€"},{"name":"Antipasti Rughetta (Légumes marinés)","price":"8.00€"},{"name":"Carpaccio Rughetta","price":"8.00€"},{"name":"Parma Mozzarella","price":"8.00€"},{"name":"Assortiment de fromages italiens","price":"9.00€"},{"name":"Assortiment de charcuteries","price":"10.00€"}]},{"category":"Pâtes Fraîches","items":[{"name":"Spaghetti Bolognese","price":"13.00€"},{"name":"Tagliatelle Carbonara","price":"14.00€"},{"name":"Lasagne al forno","price":"14.00€"},{"name":"Tagliatelle ai funghi","price":"14.00€"},{"name":"Penne al Arrabiata","price":"14.00€"},{"name":"Tagliolini Rughetta","price":"15.00€"},{"name":"Gnocchi al pesto","price":"15.00€"},{"name":"Penne Siciliana","price":"16.00€"},{"name":"Raviolone crema e basilico","price":"16.00€"}]},{"category":"Pizzas","items":[{"name":"Margherita","price":"11.00€"},{"name":"Napoletana","price":"13.50€"},{"name":"Diavola","price":"14.50€"},{"name":"4 Fromages (Quattro formaggi)","price":"15.00€"}]},{"category":"Desserts","items":[{"name":"Mousse au chocolat maison","price":"7.00€"},{"name":"Panna Cotta (coulis fraise ou caramel)","price":"8.00€"},{"name":"Pizza au Nutella (pour 2)","price":"9.50€"},{"name":"Tiramisu maison","price":"9.50€"}]},{"category":"Glaces & Coupes","items":[{"name":"Gelato (3 boules, parfums au choix)","price":"7.00€"},{"name":"Sorbet (3 boules, parfums au choix)","price":"7.00€"},{"name":"Coupe Amarena","price":"8.00€"},{"name":"Coupe Biancaneve","price":"8.00€"},{"name":"Affogato al caffè","price":"8.00€"}]},{"category":"Boissons","items":[{"name":"Café Espresso","price":"2.50€"},{"name":"Bouteille d''eau (1/2L)","price":"3.50€"},{"name":"Bouteille d''eau (1L)","price":"5.00€"}]},{"category":"Vins & Bulles","items":[{"name":"Prosecco (Flûte)","price":"7.00€"},{"name":"Champagne Gauthier (Coupe)","price":"10.00€"},{"name":"Prosecco (Bouteille)","price":"39.00€"},{"name":"Champagne Gauthier (Bouteille)","price":"65.00€"},{"name":"Champagne Ruinart (Bouteille)","price":"95.00€"}]}]}', '{"hero":"https://maps.googleapis.com/maps/api/place/photo?maxwidth=1600&photo_reference=ATCDNfXniz8orcHxxHoBtUzRxjWQhMPNGZEAiG3p43lJrs_9_aAWnQIYppYjmHbGAnbRP3DjIePxVDlthI1U3Of_y3oqVWVxGTi18hiEQqVBe-4nin3-h8XwROCe02STQA5Xc0GBGyml_-3P9HyxU30RdxcX8ALb5S1_sp8YYvJlt8vuww56nBy9FBoAPCb26uTAFqkeCzvfMJQH_DwhA4jv33hJZ3o5fhQsJfBYAjliyczA2BniJYGWvDM9zjDScu6h-enCSE90VzenwQmf1To1Hj6eaZMlTTXnUrp9tSyo4tyKXySKUjouD474h2-I4DLCwkcV0znycoNG6rnI-pJivdrPm6qCSxHTbpTfIJcUfKY3_GhIx9vb9GclRoPYPb0KasAYFtWE0ZPgb_Nk5gzja6rn9JoC52ghhcploJUXKRhjlbYlkWk_kNlVdD4D12IwYx2kCdRQq9hJQrfJ85Y1X_XPyY4vhIcruzLh6cUohA9EUKCX317ReAgUIO1XbSC5cM4uGGiQvCCZlMw_3Af80wzJqE4qa9MSIjDmeADH_hceJ8PwlKOgTJTEqd2k11dMZ_3H6cBS&key=AIzaSyDpkuHPvH-X8hZrLrpZbyC2Hi39iAfrLKM","gallery":[]}', '[]', NULL, '{"insider_tip":"• Les portions s''y avèrent particulièrement copieuses, prévoyez un appétit solide pour attaquer leurs assiettes de pâtes ou laissez-vous tenter par le doggy bag.\n• Au regard de son emplacement (et de l''affluence de touristes), ses prix très modérés en font une adresse locale exceptionnelle et véritablement préservée.\n• Les pizzas au format géant et particulièrement garnies tombent quasiment toutes hors de l''assiette. La ''4 fromages'' y est régulièrement plébiscitée.","specials":{"cuisine":["Pizza 4 fromages","Tagliolini Rughetta","Pizza au Nutella","Pizza Diavola"],"drinks":["Prosecco (7€)","Aperol Spritz"],"must_eat":"Cuisine italienne classique et très généreuse. L''endroit excelle tant par ses authentiques pizzas romaines à pâte fine comme la Diavola ou la 4 Formaggi, que par ses plats de pâtes fraîches copieusement servis comme les Tagliolini maison. Le Tiramisu et la spectaculaire Pizza au Nutella terminent de mettre tout le monde d''accord.","must_drink":"L''établissement dispose d''une très belle carte de vins italiens musclés. On peut également débuter son dîner par des valeurs sûres servies au comptoir comme le Prosecco (7€) ou de très bons Spritz."},"expert_catchline":"Trattoria authentique et généreuse, une bulle d''Italie abordable au coeur de la rue Lepic."}', 'Installée dans la très charmante rue Lepic, La Rughetta est une trattoria familiale où vit l''esprit authentique et chaleureux de l''Italie. Reconnue par une multitude d''habitués de Montmartre comme une adresse refuge incontournable au rapport qualité-prix bluffant, on y vient pour un service impeccable et bienveillant, typique de l''hospitalité italienne. Passé sa devanture accueillante, c''est un festival de parfums d''herbes aromatiques et de pâte à pain dorée qui attend les convives.', '• Les portions s''y avèrent particulièrement copieuses, prévoyez un appétit solide pour attaquer leurs assiettes de pâtes ou laissez-vous tenter par le doggy bag.
INSERT INTO places_fts VALUES ('poi-la-rughetta', 'La Rughetta', 'restaurant', 'italien pizzeria', '41 Rue Lepic', '', 'Installée dans la très charmante rue Lepic, La Rughetta est une trattoria familiale où vit l''esprit authentique et chaleureux de l''Italie. Reconnue par une multitude d''habitués de Montmartre comme une adresse refuge incontournable au rapport qualité-prix bluffant, on y vient pour un service impeccable et bienveillant, typique de l''hospitalité italienne. Passé sa devanture accueillante, c''est un festival de parfums d''herbes aromatiques et de pâte à pain dorée qui attend les convives.');
