INSERT INTO places_fts VALUES ('poi-bon-jo', 'Bon Jo', 'restaurant', 'brunch australien café montmartre healthy', '10 Rue Lamarck, 75018 Paris, France', '', 'Niché au pied du Sacré-Cœur, Bon Jo est l''escale brunch par excellence du 18e. Entre influences australiennes et élégance parisienne, ce café baigné de lumière propose une carte courte mais ultra-maîtrisée, où le café de spécialité côtoie des assiettes généreuses. Un lieu calme et serein, loin du tumulte touristique de la place du Tertre.');
