INSERT INTO places_fts VALUES ('poi-bouillon-pigalle', 'Bouillon Pigalle', 'restaurant', 'français bouillon traditionnel populaire brasserie', '22 Bd de Clichy, 75018 Paris, France', '', 'Le renouveau du bouillon parisien à Pigalle. Une immense brasserie démocratique où l''on savoure les classiques de la cuisine bourgeoise (œuf mayo, saucisse-purée, profiterole) à des prix imbattables. Un lieu vibrant, bruyant et convivial qui capture l''énergie du quartier.');
