INSERT INTO places_fts VALUES ('poi-l-ete-en-pente-douce', 'L''Été en Pente Douce', 'restaurant', 'français cuisine-du-marché terrasse montmartre', '8 Rue Paul Albert, 75018 Paris, France', '', 'Situé sur la mythique rue Muller, ce bistrot bucolique offre l''une des terrasses les plus charmantes de Montmartre. Avec son ambiance de village et sa cuisine de marché fraîche et colorée, c''est le lieu idéal pour une halte apaisante après l''ascension des marches du Sacré-Cœur.');
