xmWAthz7iust3Fr4IodVjbUG19UYnehNjYEvT32yzVM7SU4c5FqtcKMsxfoJ_OyBjZyo2ie7pApNVMOAWOmGsLtTfEwf8BhEGTWZsjBzVxSd7m3aJy9vEWnY03tR9bpdIBx-2MGqQm5cxwOQTPZLR2QyXjAQ91HzzF48-ZNHyGLo0lvyNUInJI","AU_ZVEHKzGbI5E_tq-qEK8yFPA8Xqk6lOON2Pg-RPWw35mcY39o4MisYItQvSpRdL3w3Z6l1nCx2oD-9L61h4Nn7qkGhl9h5s5b_WVm6AjpKG6gnoI7AQqBHVHiEWLd4fAoUv8XZAQNcftaib0bw1it84ires5hsdkdZznss2jrgL8mh8W_WVzAgo1qYbMvQg9a3gDW_L-C7YByS1qnxgPSM4g6Jj3fSwD8cbTC06bUxfKpCWzS5D0qlRhKiFzQoNR_Qwf-5MdyIRE8tjMHnCS_4fY2sYKR3oNr_KYIsN0ztReQ"]', NULL, '{"insider_tip":"• **La Table de Renoir** : Demandez une place en terrasse pour vous imprégner de l''atmosphère qui a inspiré le célèbre peintre.\n• **Le Coq au Vin** : C''est une recette inchangée, rustique et réconfortante, exactement ce qu''on attend d''une telle institution.\n• **Visite du Moulin** : Le moulin lui-même ne se visite pas de l''intérieur, mais le restaurant est le seul point d''accès pour l''admirer de si près.","specials":{"cuisine":["Cuisine bourgeoise traditionnelle","Plats signatures classiques","Atmosphère historique"],"drinks":["Belle sélection de vins (150 réf)","Cocktails classiques","Cave à champagne"],"must_eat":"Le Confit de Canard (26€) : une cuisson parfaite, une peau croustillante et des pommes grenailles fondantes."}}', 'Le Moulin de la Galette est une icône vivante de l''histoire de Montmartre. Mentionné dès 1622 et immortalisé par Renoir, ce lieu mythique propose aujourd''hui une expérience de brasserie chic et intemporelle. Sous l''imposant moulin en bois, on déguste les grands classiques de la cuisine bourgeoise française — Coq au vin, Sole meunière, Escargots — dans un cadre qui respire l''âme bohème du XIXe siècle. Sa terrasse ombragée est l''un des secrets les mieux gardés de la Butte pour un déjeuner hors du temps.', '• **La Table de Renoir** : Demandez une place en terrasse pour vous imprégner de l''atmosphère qui a inspiré le célèbre peintre.
INSERT INTO places_fts VALUES ('poi-le-moulin-de-la-galette', 'Le Moulin de la Galette', 'restaurant', 'brasserie historique chic traditionnel', '83 Rue Lepic, 75018 Paris, France', '', 'Le Moulin de la Galette est une icône vivante de l''histoire de Montmartre. Mentionné dès 1622 et immortalisé par Renoir, ce lieu mythique propose aujourd''hui une expérience de brasserie chic et intemporelle. Sous l''imposant moulin en bois, on déguste les grands classiques de la cuisine bourgeoise française — Coq au vin, Sole meunière, Escargots — dans un cadre qui respire l''âme bohème du XIXe siècle. Sa terrasse ombragée est l''un des secrets les mieux gardés de la Butte pour un déjeuner hors du temps.');
