INSERT INTO places_fts VALUES ('poi-le-vrai-paris', 'Le vrai Paris', 'restaurant', 'brasserie bistrot terrasse fleurie cuisine de terroir', '33 Rue des Abbesses, 75018 Paris, France', '', 'Bistrot parisien emblématique de la rue des Abbesses, Le Vrai Paris séduit par sa devanture fleurie spectaculaire et son atmosphère survoltée. On y déguste les grands classiques du terroir français dans un décor rétro soigné. Sa terrasse chauffée, idéalement placée, est l''un des meilleurs postes d''observation pour capturer l''esprit bohème et vibrant de Montmartre.');
