INSERT INTO places_fts VALUES ('poi-bulot-bulot', 'Bulot Bulot Seafood Bar', 'restaurant', 'poisson fruits de mer crustacés martyrs insolite', '83 Rue des Martyrs, 75018 Paris, France', '', 'À deux pas de Pigalle, Bulot Bulot est l''ambassade de la côte normande dans le 18e. Ici, pas de chichis : on s''installe au bar ou en terrasse pour déguster des huîtres ultra-fraîches, des bulots à l''aïoli et surtout leurs célèbres Lobster Rolls. L''ambiance est iodée, conviviale et délicieusement rétro. Une escale maritime indispensable en plein Paris.');
