fUQ90HGapFx5pUGmqY9bV1DjydZ_OZNRr_2o32yRiTJpnCH9tGZ2YWVp3-gEGPi4d-C8FT_gRYR4OGGhIOfEA1igYqmBI-pH7WJi8MYNg3MYkml5Jtd6-OiMbjr0uSK7nKzPVWc_8uzBHGF4V8nBATFplSeEE2YVhtZZ1Xxi1X9afH4TyCBZfmTNZBp8neq_eGyEobsGeMWTn2ZohriTeqhvq1wAnDeFBorqtu9EFWeW1ePylMPIyhiI5QcgsinQraN5OYp2fWwAvd0yqeYCN6Bym6MyvHNMRAKl1gFg0XPSTFm7ndUfA9C5nVEC_1r9XP3SMRXl5_tl7CIT5zR05y4bENTWNReGoV2knjRZV4SIYg8KwA48vNlr0aTO7Na5hr9-HYiyUxriZ3XeQnkc0wpOiY5MmlQgQqjYKycdFWPpngt2pp9cLheImMRBrt-&key=AIzaSyDpkuHPvH-X8hZrLrpZbyC2Hi39iAfrLKM"]', NULL, '{"insider_tip":"• La pâte est cuite au four à pierre, garantissant un croustillant parfait.\n• Ne soyez pas surpris par l''étroitesse du lieu, c''est ce qui fait son charme montmartrois.\n• Ils proposent souvent une formule ''Pizza pour deux'' très avantageuse.","specials":{"cuisine":["Italien","Pizza"],"drinks":["Vins Italiens","Softs"],"must_eat":"Pizza Del Mondo & Tiramisu Maison.","expert_catchline":"L''italien généreux et authentique caché au pied de la Butte."}}', 'Situé dans la charmante rue des Trois Frères, à quelques volées de marches du Sacré-Cœur, Pizza Del Mondo est l''archétype du petit italien de quartier sans prétention mais extrêmement généreux. Connu pour son ambiance intime et son accueil familial, l''établissement mise sur une cuisson au four à pierre pour des pizzas croustillantes. C''est l''escale idéale après une balade dans les ruelles de Montmartre, loin des pièges à touristes de la Place du Tertre.', '• La pâte est cuite au four à pierre, garantissant un croustillant parfait.
INSERT INTO places_fts VALUES ('poi-pizza-del-mondo', 'Pizza del Mondo', 'restaurant', 'italien pizza pates montmartre fait-maison', '16 Rue des Trois Frères, 75018 Paris', '', 'Situé dans la charmante rue des Trois Frères, à quelques volées de marches du Sacré-Cœur, Pizza Del Mondo est l''archétype du petit italien de quartier sans prétention mais extrêmement généreux. Connu pour son ambiance intime et son accueil familial, l''établissement mise sur une cuisson au four à pierre pour des pizzas croustillantes. C''est l''escale idéale après une balade dans les ruelles de Montmartre, loin des pièges à touristes de la Place du Tertre.');
INSERT INTO places VALUES ('poi-024', 'Parc des Buttes-Chaumont', 'buttes-chaumont', 'parc', 'parc-romantique', 'chill', 48.88095, 2.382761, 19, '1 Rue Botzaris', '#8ccaf7', 'pin', 1, 4.6, 0, '/images/buttes-chaumont.jpg', NULL, 0, 1, '€', 0, 0, 0, 0, 0, 50, '{"chill":24.5,"festif":5,"culturel":7}', '{}', '["parc","parc-romantique"]', '{"standard":"","display":"","detailed":""}', '{"reservation_policy":null,"accessibility":false,"wifi":false,"opening_hours_raw":"","action_type":"site","action_url":"","terrace":false,"happy_hour":null}', '{"avg_budget":2,"is_free":true,"pint_price":0,"cocktail_price":0,"coffee_price":0,"dish_price":0,"menu_items":[]}', '{"hero":"/images/buttes-chaumont.jpg","gallery":[]}', '[]', NULL, '{"insider_tip":"Prépare tes mollets, ça grimpe sec !","specials":{"cuisine":[],"drinks":[]}}', 'Le parc le plus escarpé, romantique et ''montagnard'' de Paris. Construit sous Napoléon III sur d''anciennes carrières de gypse, c''est un chef-d''œuvre de paysage artificiel : fausses falaises, grotte avec cascade, pont suspendu par Gustave Eiffel et le fameux Temple de la Sibylle perché sur son piton rocheux qui offre une vue sublime sur Montmartre. C''est le spot préféré des parisiens pour les pique-niques en pente, les apéros qui s''éternisent et les joggings cardio (ça grimpe !).', 'Prépare tes mollets, ça grimpe sec !', 'Buttes Chaumont', '[7]', '[]', NULL, NULL);
INSERT INTO places_fts VALUES ('poi-024', 'Parc des Buttes-Chaumont', 'parc', 'parc-romantique', '1 Rue Botzaris', '', 'Le parc le plus escarpé, romantique et ''montagnard'' de Paris. Construit sous Napoléon III sur d''anciennes carrières de gypse, c''est un chef-d''œuvre de paysage artificiel : fausses falaises, grotte avec cascade, pont suspendu par Gustave Eiffel et le fameux Temple de la Sibylle perché sur son piton rocheux qui offre une vue sublime sur Montmartre. C''est le spot préféré des parisiens pour les pique-niques en pente, les apéros qui s''éternisent et les joggings cardio (ça grimpe !).');
