INSERT INTO places_fts VALUES ('poi-zhao-menilmontant', 'La Taverne de Zhao', 'restaurant', 'chinois noodles biang-biang authentique quartier', '42 rue de Ménilmontant, 75020 Paris, France', '', 'Dernière-née du groupe, la Taverne Ménilmontant apporte les saveurs de Xi''an dans l''est parisien. Le décor y est particulièrement chaleureux, parfaitement intégré à l''esprit populaire et artistique du 20e arrondissement. On y retrouve l''excellence des Biang Biang tirées à la main.');
INSERT INTO places VALUES ('poi-006', 'La Bellevilloise', 'la-bellevilloise', 'club', 'espace-culturel', 'festif', 48.868351, 2.392157, 20, '19-21 Rue Boyer', '#ffab60', 'pin', 1, 4.3, 0, 'https://upload.wikimedia.org/wikipedia/commons/f/f6/La_Bellevilloise.jpg', NULL, 0, 0, '€', 8, NULL, NULL, 0, 0, 50, '{"chill":10,"festif":30,"culturel":5}', '{}', '["club","espace-culturel"]', '{"standard":"","display":"","detailed":""}', '{"reservation_policy":null,"accessibility":false,"wifi":false,"opening_hours_raw":"","action_type":"site","action_url":"","terrace":false,"happy_hour":null}', '{"avg_budget":8,"is_free":false,"pint_price":8,"cocktail_price":0,"coffee_price":0,"dish_price":0,"menu_items":[]}', '{"hero":"https://upload.wikimedia.org/wikipedia/commons/f/f6/La_Bellevilloise.jpg","gallery":[]}', '[]', NULL, '{"insider_tip":"Le brunch du dimanche avec jazz live est magique, mais réservez 2 semaines à l avance.","specials":{"cuisine":[],"drinks":[]}}', 'Fondée en 1877 comme première coopérative ouvrière de Paris, la Bellevilloise est devenue un haut lieu culturel indépendant. Dans ses halles majestueuses plantées d''oliviers centenaires, on vient écouter du jazz lors du brunch dominical, découvrir une expo engagée ou danser lors des soirées clubbing. Un lieu chargé d''histoire sociale qui continue de faire vibrer l''est parisien avec une programmation éclectique et ouverte.', 'Le brunch du dimanche avec jazz live est magique, mais réservez 2 semaines à l avance.', 'Ménilmontant', '[2]', '[]', NULL, NULL);
INSERT INTO places_fts VALUES ('poi-006', 'La Bellevilloise', 'club', 'espace-culturel', '19-21 Rue Boyer', '', 'Fondée en 1877 comme première coopérative ouvrière de Paris, la Bellevilloise est devenue un haut lieu culturel indépendant. Dans ses halles majestueuses plantées d''oliviers centenaires, on vient écouter du jazz lors du brunch dominical, découvrir une expo engagée ou danser lors des soirées clubbing. Un lieu chargé d''histoire sociale qui continue de faire vibrer l''est parisien avec une programmation éclectique et ouverte.');
